INSERT INTO public.photos VALUES (22969, 'Convento Santo Domingo aв”ңв–’os 90', 'Foto SIPCA. Vista del refectorio del convento de Santo Domingo (siglo XIV, mudв”ңВ®jar), desde el patio del antiguo instituto Luis Buв”ңв–’uel. En 2001 serв”ңГӯ abierto restaurado como Museo del Agua.', 1990, 1990, 1999, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65833700, -0.88861500, '0101000020E6100000738577B9886FECBF965F066344D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14950154847.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14950154847.webp', 'https://www.flickr.com/photos/zaragozaantigua/14950154847/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23060, 'Calle de los Aguadores 1994', 'Imagen centrada en el inmueble del nв”¬в•‘ 13 de la calle de los Aguadores esquinero con la calle de las Armas. El tradicional andamiaje de puertas de madera asentadas sobre maderos y troncos salientes, seв”ңв–’ala el derribo de esta casa, que como sus vecinas de calle, a la derecha, posiblemente se tratara de una de las antiguas parcelas unifamiliares de los siglos XVI-XVII de este barrio, remodeladas posteriormente. A principios del siglo XXI se construirв”ңГӯ sobre su solar una moderna vivienda. Un mayor pasea por este antiquв”ңВЎsima encrucijada del primer ensanche de la ciudad: San Pablo.', 1994, 1994, 1994, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65701800, -0.88704900, '0101000020E610000056629E95B462ECBF1171732A19D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50496371053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50496371053.webp', 'https://www.flickr.com/photos/zaragozaantigua/50496371053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23154, 'Avenida Ranillas 2007', 'Foto: Josв”ңВ® Miguel Marco. Imagen tomada desde el puente de La Almozara, que muestra las instalaciones de la chatarrerrв”ңВЎa Desguaces Puente de Santiago, en la avenida de Ranillas 7. Estos solares ribereв”ңв–’os serв”ңГӯn objeto de una operaciв”ңв”Ӯn urbanв”ңВЎstica entre el Club Helios y el Ayuntamiento, de resultas de la cual los primeros obtendrв”ңГӯn terrenos para su expansiв”ңв”Ӯn, ademв”ңГӯs de licencia para levantar un bloque hostelero de lujo, con restaurantes y discoteca. El propietario del desguace demandв”ңв”Ӯ al Ayuntamiento, lo que retrasв”ңв”Ӯ la inauguraciв”ңв”Ӯn del monstruoso Complejo Aura hasta 2012. Todo ello enmarcado en el plan de riberas, de acompaв”ңв–’amiento de la Expo 2008. Los promotores, en vista de la dilaciв”ңв”Ӯn, montaron un remedo ibicenco provisional (Cafв”ңВ® del Mar). Al fondo, el Pilar. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2007, 2007, 2007, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.66196000, -0.88875700, '0101000020E610000010EA2285B270ECBF4DA1F31ABBD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32347839636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32347839636.webp', 'https://www.flickr.com/photos/zaragozaantigua/32347839636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23230, 'Rв”ңВЎo Ebro 2050', 'Recreaciв”ңв”Ӯn efectuada sobre una fotografв”ңВЎa de 2007. Muestra, vista desde el puente de La Almozara, una Zaragoza mв”ңГӯs cв”ңГӯlida, con el rв”ңВЎo Ebro convertido en un arroyuelo, hacia el aв”ңв–’o 2050, como consecuencia del cambio climв”ңГӯtico que estв”ңГӯ llevando a un calentamiento global debido a las emisiones de CO2. Los autores de esta imagen y las que la acompaв”ңв–’an dijeron haberse inspirado en un informe del Panel Intergubernamental sobre Cambio Climв”ңГӯtico de Naciones Unidas. Fuente: "Photoclima: Imв”ңГӯgenes de un futuro afectado por el cambio climв”ңГӯtico", Greenpeace, 2007.', 2024, 2020, 2029, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.66004300, -0.88796900, '0101000020E61000001094DBF63D6AECBF147AFD497CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31746760983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31746760983.webp', 'https://www.flickr.com/photos/zaragozaantigua/31746760983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23991, 'Calle Democracia 1916', 'Grupo de niв”ңв–’os saliendo de la puerta del Ayuntamiento de Zaragoza en las celebraciones de la Fiesta del в”ңГјrbol. Se trata de la reciente sede del consistorio, en la calle de la Democracia (hoy Predicadores). Al fondo, la torre de Santiago del templo del Pilar. Fuente: La Hormiga de Oro, 1916.', 1916, 1916, 1916, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65800400, -0.88891600, '0101000020E610000030849CF7FF71ECBF8F519E7939D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19176511871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19176511871.webp', 'https://www.flickr.com/photos/zaragozaantigua/19176511871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24121, 'Calle de la Democracia, 1931', 'Aspecto de la manifestaciв”ңв”Ӯn convocada el viernes 1 de mayo de 1931 con motivo de la Fiesta del Trabajo, cuyo recorrido transcurriв”ңв”Ӯ entre la plaza de la Libertad, donde estaba residenciada la Casa Consistorial, hasta la plaza de Aragв”ңв”Ӯn ante la sede del Gobierno civil. La fotografв”ңВЎa ha sido capturada en la calle de la Democracia, en el tramo comprendido entre la calle de la Golondrina (a la izquierda) y la plaza de Lanuza. Hacia el fondo y a la derecha, el soleado y gran inmueble de la antigua cв”ңГӯrcel habilitada en el palacio de los Duques de Villahermosa. Esta manifestaciв”ңв”Ӯn constituyв”ңв”Ӯ un refrendo popular de adhesiв”ңв”Ӯn al Gobierno provisional de la Repв”ңв•‘blica.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65725000, -0.88373400, '0101000020E6100000DC9F8B868C47ECBFE3A59BC420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53691751613.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53691751613.webp', 'https://www.flickr.com/photos/zaragozaantigua/53691751613/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24218, 'Ayuntamiento. Interior. 1961', 'Ayuntamiento de Zaragoza/Archivo JARKE-JARIA. Octubre 1961. La reina de las fiestas matronales, acompaв”ңв–’ada con sus damas de honor, visitan el Ayuntamiento, y se fotografв”ңВЎan en la mesa que preside las Sesiones Plenarias. Se trata aв”ңв•‘n del edificio consistorial de la Plaza de Santo Domingo, pues el nuevo edificio de la Plaza del Pilar no se estrenarв”ңГӯ hasta unos aв”ңв–’os despuв”ңВ®s. Preside la estancia una mayestв”ңГӯtica pintura del jefe del Estado, que en esa ocasiв”ңв”Ӯn saliв”ңв”Ӯ algo demediado. Ups...', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65802800, -0.88888900, '0101000020E6100000CAC51858C771ECBF18EDF1423AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14903858696.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14903858696.webp', 'https://www.flickr.com/photos/zaragozaantigua/14903858696/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24365, 'Convento de las Lucв”ңВЎas Aв”ңв–’os 30', 'AHPZ. Josв”ңВ® Galiay Saraв”ңв–’ana. Aв”ңв–’os 30. "Zaragoza. Muro del Convento de las Lucв”ңВЎas. Tranvв”ңВЎa." En el siglo XVI llega una comunidad de monjas cistercienses de la mano del arzobispo, y fundan otro convento junto a la ermita de Santa Lucв”ңВЎa, cerca de las Fecetas y la Puerta de Sancho. Durante los combates de 1808-09 el convento resulta destruido, y tras la desamortizaciв”ңв”Ӯn de 1835 las monjas deben marcharse, aunque vuelven en 1850. En la imagen, el Convento en la calle 29 de septiembre, al paso del tranvв”ңВЎa 31 de la Lв”ңВЎnea 7 "Ayuntamiento", pues muy cerca, en la confluencia de la plaza de la Libertad, con Democracia, estaba la Casa Consistorial. En 1967 el convento es derribado, y la comunidad se traslada a su actual ubicaciв”ңв”Ӯn en el barrio de Casablanca.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65794000, -0.88964500, '0101000020E6100000F29881CAF877ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15236484129.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15236484129.webp', 'https://www.flickr.com/photos/zaragozaantigua/15236484129/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24369, 'Azucarera Agrв”ңВЎcola del Pilar c.1955', 'Tras la supresiв”ңв”Ӯn de la Ley Osma (1907) impuesta por el monopolio azucarero, se produce un "boom" (entre 1911 y 1913) de una segunda generaciв”ңв”Ӯn de azucareras de Aragв”ңв”Ӯn, hasta con cinco nuevas instalaciones. La zaragozana "Alcoholera Agrв”ңВЎcola del Pilar", constituida en 1911, desde 1919 quedв”ңв”Ӯ configurada como "Azucarera Agrв”ңВЎcola del Pilar", dentro del grupo SGA (Sociedad General Azucarera)-CIA (Compaв”ңв–’в”ңВЎa de Industrias Agrв”ңВЎcolas). Estuvo funcionando hasta la campaв”ңв–’a 1962-1963. En la imagen, vista aв”ңВ®rea de la urbana zona en que estaba enclavada esta industria, en la calle 29 de septiembre, justo al lado de la Casa Consistorial de la Plaza de Santo Domingo (abajo, a la derecha). Justo enfrente, el Convento de las Lucв”ңВЎas, en la calle de Santa Lucв”ңВЎa, con su caracterв”ңВЎstica espadaв”ңв–’a. Un poco mв”ңГӯs hacia la izquierda, el Convento de las Fecetas, poco antes del cruce del paseo de Mв”¬В¬ Agustв”ңВЎn, el paso a nivel de La Almozara, y el Camino de Monzalbarba. Arriba, las vв”ңВЎas del ferrocarril y el puente del ferrocarril. A la derecha, el incipiente paseo de Echegaray y Caballero, junto a la ribera del Ebro. Fuente visual: Mв”¬В¬ Pilar Biel Ibв”ңГӯв”ңв–’ez, Zaragoza y la industrializaciв”ңв”Ӯn: la arquitectura industrial en la capital aragonesa entre 1875-1936, IFC.', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65838800, -0.88980600, '0101000020E61000003F1BB96E4A79ECBF180AD80E46D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15547274458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15547274458.webp', 'https://www.flickr.com/photos/zaragozaantigua/15547274458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24376, 'Convento de Santa Lucв”ңВЎa c.1945', 'Imagen centrada en el в”ңГӯbside de la iglesia del desaparecido convento cisterciense de "las Lucв”ңВЎas" y los restos de su interesante torre adosada, desmochada y reconvertida apenas de una espadaв”ңв–’a con doble campana. La foto estв”ңГӯ capturada en el chaflв”ңГӯn entre la calle de Santa Lucв”ңВЎa (derecha), y la plaza de Santo Domingo (izquierda). Josв”ңВ® Galiay tomв”ңв”Ӯ esta visual parta ilustrar su libro "Arte mudв”ңВ®jar aragonв”ңВ®s", donde perdura en papel para compararla con la cosa que, tras la venta y derribo del convento en 1967, se eleva hoy en ese mismo lugar. En el suelo y en el cielo, rastros del tendido de la Lв”ңВЎnea 7 del tranvв”ңВЎa "Ayuntamiento". Fuente visual: AHPZ, Josв”ңВ® Galiay Saraв”ңв–’ana. "Zaragoza. Iglesia de San Miguel de los Navarros (sic). в”ңГјbside mudв”ңВ®jar." 1900-1952.', 1945, 1945, 1945, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65794000, -0.88964500, '0101000020E6100000F29881CAF877ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18494493835.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18494493835.webp', 'https://www.flickr.com/photos/zaragozaantigua/18494493835/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24406, 'Convento de Santa Lucв”ңВЎa aв”ңв–’os 30', 'Acuarela de Ambrosio Ruste, con una vista del convento de Santa Lucв”ңВЎa, en la calle 29 de septiembre, luego Santa Lucв”ңВЎa. Fuente: Lв”ңГӯminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65804100, -0.88976500, '0101000020E61000009B030473F478ECBFAC36FFAF3AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31629173343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31629173343.webp', 'https://www.flickr.com/photos/zaragozaantigua/31629173343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24418, 'Santa Lucв”ңВЎa 1890', 'Imagen centrada en la fachada de la iglesia del convento cisterciense de Santa Lucв”ңВЎa en la calle del Veintinueve de Septiembre. Al fondo, la plaza de la Libertad, y las casonas del final de la calle de la Democracia, frente al antiguo convento dominico de Santo Domingo. Tres dв”ңВ®cadas mв”ңГӯs tarde, por aquв”ңВЎ pasarв”ңГӯ la tranviaria Lв”ңВЎnea 7 "Ayuntamiento". En 1967 este convento serв”ңГӯ vendido y derribado, la comunidad se trasladarв”ңГӯ al barrio de Casablanca, y sobre este solar se levantarв”ңГӯn unas casas-cosa ciertamente impactantes. Fuente visual: Г”ГҮВЈZaragoza Artв”ңВЎstica, Monumental e Histв”ңв”ӮricaГ”ГҮГҳ, Anselmo y Pedro Gascв”ңв”Ӯn de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65804100, -0.88976500, '0101000020E61000009B030473F478ECBFAC36FFAF3AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34618443955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34618443955.webp', 'https://www.flickr.com/photos/zaragozaantigua/34618443955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24422, 'Convento de Santo Domingo 1999', 'Imagen interior del refectorio (comedor comв”ңв•‘n) del convento de Santo Domingo de la Orden de Predicadores realizado a principios del siglo XIV, capturada durante las obras de restauraciв”ңв”Ӯn y adecuaciв”ңв”Ӯn para Biblioteca del Agua y del Medio Ambiente, proyectadas y dirigidas por el arquitecto municipal Ricardo Usв”ңв”Ӯn Garcв”ңВЎa. La luz natural inunda la estancia desde su lado sur. Estas originales instalaciones estuvieron previamente integradas en el Colegio Militar preparatorio allв”ңВЎ ubicado a finales del siglo XIX, luego Casa Consistorial, y luego Instituto de Enseв”ңв–’anza Secundaria. Fuente visual: AMZ.', 1999, 1999, 1999, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65845500, -0.88865700, '0101000020E61000002E910BCEE06FECBF9F71E14048D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38058368755.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38058368755.webp', 'https://www.flickr.com/photos/zaragozaantigua/38058368755/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24455, 'Anв”ңВЎs ferroviario 1936', 'Comparativa en una sola imagen de una postal circulada en 1936 con un anuncio de "Anв”ңВЎs, Ron y Coв”ңв–’ac Ferroviario"; y su versiв”ңв”Ӯn en cartel de dos dв”ңВ®cadas despuв”ңВ®s, modificando algunos elementos, como la botella-locomotora o las banderas que la engalanan: primero la versiв”ңв”Ӯn oficial de la Repв”ңв•‘blica y luego la de la dictadura. La Industrial Licorera Espaв”ңв–’ola tuvo fв”ңГӯbrica en el Camino de San Josв”ңВ® de Zaragoza, entre los aв”ңв–’os 20 y 70 del siglo XX. En los dibujos, el Puente del Ferrocarril de La Almozara con el Pilar al fondo.', 1936, 1936, 1936, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.66154300, -0.88990800, '0101000020E61000004F5C8E57207AECBFE9F2E670ADD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18736335073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18736335073.webp', 'https://www.flickr.com/photos/zaragozaantigua/18736335073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24481, 'P.в”¬в•‘ de Echegaray y Caballero 1964', 'Imagen del dieciochesco edificio del antiguo Almacв”ңВ®n o Pв”ңв”Ӯsito de la Sal de la ciudad, sito en el paseo del Ebro, en el tramo entre la puerta de la Triperв”ңВЎa (a su izquierda), y el palacio de Villahermosa (a su derecha). El vial de acceso luego redenominado paseo de Echegaray y Caballero. Este edificio absolutamente в”ңв•‘nico, y su entorno no menos reseв”ңв–’able, fueron demolidos aв”ңв–’os despuв”ңВ®s para construir lo que hoy hay. Sic transit gloria urbis. Fuente: Fotografв”ңВЎa Cristв”ңв”Ӯbal Guitart Aparicio (www.facebook.com/photo.php?fbid=1692438180979881&set=...)', 1964, 1964, 1964, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65786700, -0.88343300, '0101000020E61000001FA166481545ECBF0F0F61FC34D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22963689026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22963689026.webp', 'https://www.flickr.com/photos/zaragozaantigua/22963689026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24551, 'Puente Almozara 1987', 'Aprovechando la estructura del puente del ferrocarril, se puso en servicio para vehв”ңВЎculos rodados el nuevo puente de la Almozara en 1987. En la foto, el puente sobre el Ebro, con el Actur al norte y la plaza de Europa con el barrio de la Almozara al sur. Fuente: Zaragoza 1908-2008. FCC.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.66154300, -0.88990800, '0101000020E61000004F5C8E57207AECBFE9F2E670ADD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15091299963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15091299963.webp', 'https://www.flickr.com/photos/zaragozaantigua/15091299963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24563, 'Puente del ferrocarril 1879', '"Elevaciв”ңв”Ӯn de un puente de hierro construido sobre el Ebro en Zaragoza. Ramal de empalme de las lв”ңВЎneas de Zaragoza a Barcelona con las de Navarra y Madrid". Plano diseв”ңв–’ado con motivo del recrecimiento en 1879 del puente del ferrocarril de la Almozara. construido en 1870. Fuente: Revista de Obras Pв”ңв•‘blicas.', 1879, 1879, 1879, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.66143200, -0.89038800, '0101000020E6100000F20698F90E7EECBF9143C4CDA9D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28511299476.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28511299476.webp', 'https://www.flickr.com/photos/zaragozaantigua/28511299476/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24972, 'Club Baloncesto Helios c.1946', 'Los orв”ңВЎgenes del equipo de baloncesto de Zaragoza se remontan a los aв”ңв–’os 30 del siglo XX, en el centro de nataciв”ңв”Ӯn Helios, a orillas del Ebro. En la imagen, un partido en los aв”ңв–’os 40. De interв”ңВ®s, las vistas: a la izquierda el edificio de los baв”ңв–’os de los aв”ңв–’os 20; a la derecha, las torres del Pilar y de San Juan de los Panetes. Fuente: clubbasquet6.blogspot.com.es/p/historia-de-clubs.html', 1946, 1946, 1946, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65954000, -0.88300600, '0101000020E6100000307F85CC9541ECBFB13385CE6BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19178631149.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19178631149.webp', 'https://www.flickr.com/photos/zaragozaantigua/19178631149/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24981, 'Helios 1934', 'Canicular imagen capturada durante un encuentro de basket en la antigua pista de la "Sociedad Naturista Helios" para la prв”ңГӯctica de este deporte. A la izquierda, el original "chalet" que formaba parte de las primeras instalaciones aquв”ңВЎ construidas, notablemente mejorado en sus accesos. A su derecha, el pabellв”ңв”Ӯn para vestuarios, tras el cual estaba el camino de ingreso a la "Sociedad" desde la Arboleda de Macanaz. Al fondo, a la izquierda, paredes del Juego de Pelota. Fuente: www.lacasadelbaloncesto.es/', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65996200, -0.88450500, '0101000020E610000059C0046EDD4DECBF274D83A279D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24336377679.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24336377679.webp', 'https://www.flickr.com/photos/zaragozaantigua/24336377679/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25122, 'Calle Postigo del Ebro aв”ңв–’os 30', 'Acuarela de Ambrosio Ruste de la calle Postigo del Ebro, asв”ңВЎ denominada por el postigo, pequeв”ңв–’a puerta o trenque, aquв”ңВЎ realizado en la antigua muralla в”ңГӯrabe de rв”ңВ®jola que rodeaba a la Poblaciв”ңв”Ӯn del Rey (actual barrio de San Pablo). Este Postigo fue primero denominado "de Sorreal", y comunicaba la calle Predicadores con el paseo de la ribera, tal y como hoy hace la calle Postigo del Ebro, que comunica Predicadores con el paseo de Echegaray y Caballero. El dibujo representa el estado de esta calle. Al fondo, la ribera. A izquierda y derecha, la calle Predicadores. Fuente: Lв”ңГӯminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65773900, -0.88653400, '0101000020E61000009758198D7C5EECBFE126A3CA30D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15588714198.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15588714198.webp', 'https://www.flickr.com/photos/zaragozaantigua/15588714198/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25123, 'Vista de Zaragoza 1978', 'Colecciв”ңв”Ӯn Cв”ңВ®sar Sв”ңГӯnchez Vв”ңГӯzquez. Cв”ңВ®sar Sв”ңГӯnchez Vв”ңГӯzquez. 1978. Desde mi estudio. Fuente: zaragozacool.blogspot.com.es/2010_05_01_archive.html', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65775500, -0.88922900, '0101000020E6100000FEF334609074ECBFE7E3DA5031D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15701051259.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15701051259.webp', 'https://www.flickr.com/photos/zaragozaantigua/15701051259/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25446, 'Pasarela 1945', 'Vista de la pasarela de Macanaz y el Pilar, desde la margen izquierda. Fuente: Heraldo de Aragв”ңв”Ӯn.', 1945, 1945, 1945, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65936000, -0.88324400, '0101000020E6100000556CCCEB8843ECBF312592E865D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32385346784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32385346784.webp', 'https://www.flickr.com/photos/zaragozaantigua/32385346784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25544, 'Regatas Ebro 1934', 'Panorв”ңГӯmica imagen del rв”ңВЎo Ebro a su paso por la ciudad, poblado de piragв”ңв•қistas en un concurso organizado por el Centro Naturista Helios. La fachada de la margen derecha de Zaragoza o Paseo de la Ribera expone una muestra arqueolв”ңв”Ӯgica de un pasado del que nos separan poco mв”ңГӯs de 80 aв”ңв–’os: escaleras de acceso a las barcas para cruzar el rв”ңВЎo; el Grupo Escolar de Valentв”ңВЎn Zabala, esquina con Escobar y Antonio Pв”ңВ®rez; el dieciochesco edificio del Alfolв”ңВЎ, y sus contemporв”ңГӯneas viviendas de alquiler de la calle de los Infantes, junto a la cв”ңГӯrcel vieja de Predicadores... Fuente visual: Foto Marв”ңВЎn Chivite,"Mundo Grв”ңГӯfico" (Madrid)', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65844700, -0.88391500, '0101000020E6100000F0332E1C0849ECBF1D93C5FD47D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22061459661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22061459661.webp', 'https://www.flickr.com/photos/zaragozaantigua/22061459661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25546, 'Puente Almozara 1987', 'Vista del puente de La Almozara desde la Margen Izquierda en septiembre de 1987, a punto de ser abierto al trв”ңГӯfico tras su reconversiв”ңв”Ӯn, tras haber perdido su anterior condiciв”ңв”Ӯn de puente del ferrocarril. Fuente: Revista Nuestra Zaragoza, 1987.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.66209200, -0.88962400, '0101000020E6100000149337C0CC77ECBFBC783F6EBFD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22488006551.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22488006551.webp', 'https://www.flickr.com/photos/zaragozaantigua/22488006551/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25561, 'Puente de la Almozara 1987', 'Imagen del nuevo puente de la Almozara, antiguo del Ferrocarril, tras la transformaciв”ңв”Ӯn realizada para dar soporte a lo seis carriles de circulaciв”ңв”Ӯn rodada (tres por direcciв”ңв”Ӯn), con un espacio central para diversos servicios y conducciones. Fue inaugurado a finales de septiembre de 1987. Hemos volteado horizontalmente la imagen original, al objeto de reubicar correctamente las cosas, y no perder el sur mucho mв”ңГӯs de lo que ya estв”ңГӯ. Asв”ңВЎ, la captura se habrв”ңВЎa realizado desde la margen izquierda, con la margen derecha como telв”ңв”Ӯn de fondo al puente, donde destaca la mole de Piensos "Cia", la torre del Homenaje de la Aljaferв”ңВЎa, y los bloques en construcciв”ңв”Ӯn del primer tramo de la avenida de la Almozara. Fuente visual: Antonio Calvo Pedrв”ңв”Ӯs, AMZ.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.66143200, -0.89038800, '0101000020E6100000F20698F90E7EECBF9143C4CDA9D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30097058933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30097058933.webp', 'https://www.flickr.com/photos/zaragozaantigua/30097058933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25567, 'Playa del Ebro 1932', 'Imagen capturada desde una embarcaciв”ңв”Ӯn sobre el rв”ңВЎo Ebro, y centrada en el bullicioso frente de playa fluvial que durante la canв”ңВЎcula se formaba en el entorno de la Arboleda de Macanaz, desde la Sociedad Naturista Helios (a la izquierda) y hasta la pв”ңв•‘blica Caseta de los Baв”ңв–’os (a la derecha). Tres embarcaderos garantizaban el acceso directo desde la margen derecha, y ni las barcas, ni los baв”ңв–’os, precisaban azud artificial. Fuente visual: www.mecd.gob.es/.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65896600, -0.88306900, '0101000020E6100000C99063EB1942ECBF859675FF58D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35351641660.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35351641660.webp', 'https://www.flickr.com/photos/zaragozaantigua/35351641660/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25573, 'Helios 1974', 'Inв”ңВ®dita imagen de la inauguraciв”ңв”Ӯn a finales del mes de junio de 1974 del refrescante "lago-piscina" ubicado en la zona mв”ңГӯs occidental del Centro Nataciв”ңв”Ӯn Helios, a medio camino entre el puente de Santiago y el puente del Ferrocarril, con una interesante vista capturada desde la altura de una de las viviendas del barrio de la Ortilla, al otro lado del camino de Juslibol y a la altura de la calle de Fв”ңВ®lix Garcв”ңВЎa Gil. Como no podв”ңВЎa ser de otra forma, esta moderna instalaciв”ңв”Ӯn fue bendecida por el canв”ңв”Ӯnigo del Cabildo Juan Antonio Gracia, y a la ceremonia asistiв”ңв”Ӯ el concejal Alfredo Villalba Arlegui ademв”ңГӯs de una representaciв”ңв”Ӯn de la directiva heliв”ңв”Ӯfila. Al otro lado del rв”ңВЎo, fachada ribereв”ңв–’a vertebrada por la calle del Postigo del Ebro y comprendida entre las traseras de la antigua casa de los duques de Villahermosa, a la izquierda, y la Casa Amparo, a la derecha, por donde sobresalen las torrecillas de la iglesia del mв”ңГӯs lejano y antiguo Hospicio Provincial.', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.66084100, -0.88562200, '0101000020E610000093C7D3F20357ECBF8F6D197096D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51568617220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51568617220.webp', 'https://www.flickr.com/photos/zaragozaantigua/51568617220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25826, 'Calle de Predicadores c.1952', 'Fachada del barroco palacio de Villahermosa, en el nв”ңв•‘mero 58 de la calle Predicadores de Zaragoza. Sв”ңв”Ӯlo se conserva la fachada, del siglo XVII. En el momento de la imagen, era cв”ңГӯrcel de mujeres. Fuente visual: "Los tranvв”ңВЎas de Zaragoza", J. Peв”ңв–’a-J.M. Valero, DPZ, 1985.', 1952, 1952, 1952, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65760400, -0.88503800, '0101000020E6100000B2F336363B52ECBF01DC2C5E2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15019901070.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15019901070.webp', 'https://www.flickr.com/photos/zaragozaantigua/15019901070/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25828, 'Calle Aguadores 1951', '"Por detrв”ңГӯs, la ficha a la que estв”ңГӯ grapada la imagen lleva esta leyenda: "Zaragoza. Junio 1951. C/ Aguadores (Entrada: San Blas, 82 / Salida: Predicadores 93) ". Imagen de la calle, tramo entre Predicadores (primer plano) y San Blas (al fondo). Fuente visual: Archivo Municipal. Archivo Mora. Junio 1951.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65755200, -0.88672000, '0101000020E61000001CB1169F0260ECBFAFB5F7A92AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15143737427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15143737427.webp', 'https://www.flickr.com/photos/zaragozaantigua/15143737427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25832, 'Barrio San Pablo 2007', 'Imagen capturada desde la iglesia parroquial de San Pablo Apв”ңв”Ӯstol, con vista del inmediato espacio comprendido entre la calle de Las Armas (en primer tв”ңВ®rmino) y la de Casta в”ңГјlvarez (centro), rehabilitado poco despuв”ңВ®s mediante la construcciв”ңв”Ӯn de viviendas de protecciв”ңв”Ӯn oficial y el Centro Musical y Artв”ңВЎstico Las Armas, inaugurado en 2011. El solar que preside la imagen configura la actual plaza de Las Armas. Al fondo, el rв”ңВЎo Ebro y la Margen Izquierda.', 2007, 2007, 2007, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65708700, -0.88591400, '0101000020E6100000833122516859ECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20288957685.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20288957685.webp', 'https://www.flickr.com/photos/zaragozaantigua/20288957685/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25836, 'Casa de Amparo c.1955', '"Patio de la Casa Amparo de Zaragoza, varias monjas y gran grupo de ancianos descansando". La Casa de Amparo fue creada por el Ayuntamiento en 1850 sobre parte del antiguo convento de Santo Domingo de los PP. Dominicos. Construido bв”ңГӯsicamente en el siglo XIV, fue muy reformado por el arquitecto municipal Ricardo Magdalena. En ella viven y trabajan como asistentas algunas religiosas de la Congregaciв”ңв”Ӯn de Hijas de la Caridad de San Vicente de Paв”ңв•‘l. En la imagen, masculino sol y sombra en el patio occidental de la Casa de Amparo, leve recuerdo del previo claustro dominico. Las religiosas, perfectamente mimetizadas. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65807000, -0.88812100, '0101000020E610000091813CBB7C6BECBF473D44A33BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22879275921.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22879275921.webp', 'https://www.flickr.com/photos/zaragozaantigua/22879275921/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25842, 'Calle Las Armas 2005', 'Foto: Marina Ovejero. Vista en agosto de 2005 del solar entre la calle de Las Armas y la de Casta в”ңГјlvarez (la del edificio a la derecha), incluido en el Plan Especial de Reforma Interior (PERI) "Las Armas-Casta в”ңГјlvarez", del Plan Integral del Casco Histв”ңв”Ӯrico (1997). El proyecto de plaza, viviendas y centro cultural fue concluido en 2011, 14 aв”ңв–’os despuв”ңВ®s. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2005, 2005, 2005, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65714800, -0.88616300, '0101000020E6100000A29BFD81725BECBFDF50F86C1DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31593745161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31593745161.webp', 'https://www.flickr.com/photos/zaragozaantigua/31593745161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25856, 'Convento de Santo Domingo 1864', 'Imagen del desaparecido convento de Santo Domingo poco antes de que la Junta Revolucionaria de la ciudad decidiera a finales de 1868 derribar la iglesia, el claustro y la sala capitular, conservв”ңГӯndose el "salв”ңв”Ӯn gв”ңв”Ӯtico" o refectorio conventual, el dormitorio conventual, algunos retablos e imв”ңГӯgenes, el arco gв”ңв”Ӯtico que conectaba el claustro con el refectori y el sepulcro del cardenal Jerв”ңв”Ӯnimo Xavierre. Este terrible derribo permitiв”ңв”Ӯ erigir en su solar la Casa de Amparo y la Academia Militar Preparatoria, ademв”ңГӯs de regularizar el trazado de la calle de Predicadores. En la imagen, el convento presenta su traza otorgada por la gran reforma barroca de que fue objeto en el siglo XVII.', 1864, 1864, 1864, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65806000, -0.88789700, '0101000020E6100000ABED26F8A669ECBF2367614F3BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54387023468.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54387023468.webp', 'https://www.flickr.com/photos/zaragozaantigua/54387023468/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25976, 'Predicadores c.1900', 'El voluminoso edificio que preside la toma es la Casa de Amparo de Zaragoza, en la calle Predicadores. En la larga vida de su construcciв”ңв”Ӯn por pabellones, entre 1880 y 1940, fue ganando terreno a los restos del convento de Santo Domingo, parte de cuyos pabellones aв”ңв•‘n se ven en la imagen, a su izquierda, antes del edificio del Ayuntamiento, luego instituto Luis Buв”ңв–’uel. Entre 1885 y 1906, el arquitecto municipal Ricardo Magdalena se encargв”ңв”Ӯ de la ampliaciв”ңв”Ӯn. Al fondo, el rв”ңВЎo Ebro con el puente del ferrocarril del enlace entre las lв”ңВЎneas de Barcelona y Pamplona, por el que estв”ңГӯ transitando un tren en direcciв”ңв”Ӯn a la estaciв”ңв”Ӯn de la Almozara. Fuente visual: Fototipia L. Escolв”ңГӯ, en www.ebay.es/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65813500, -0.88782300, '0101000020E6100000185FB4C70B69ECBF2EAD86C43DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15150026036.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15150026036.webp', 'https://www.flickr.com/photos/zaragozaantigua/15150026036/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20991, 'Fв”ңГӯbrica de yeso 1855', 'Mariano Lв”ңв”Ӯpez, 23 de septiembre de 1855. Planta y alzado de la fв”ңГӯbrica de yeso y demв”ңГӯs propiedades de Vв”ңВЎctor Mariв”ңв–’osa y compaв”ңв–’в”ңВЎa, con entrada por la calle de la Puerta de Sancho (hoy Santa Lucв”ңВЎa). Estos terrenos serв”ңГӯn ocupados en 1911 por la Alcoholera Agrв”ңВЎcola del Pilar, luego Azucarera. Fuente: bibliotecavirtualdefensa.es/', 1855, 1855, 1855, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65855400, -0.89068800, '0101000020E61000009911DE1E8480ECBF33535A7F4BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30917295762.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30917295762.webp', 'https://www.flickr.com/photos/zaragozaantigua/30917295762/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21011, 'Convento de Santa Lucв”ңВЎa c.1860', 'Convento de Santa Lucв”ңВЎa de Zaragoza. Valentв”ңВЎn Carderera. Lв”ңГӯpiz y acuarela sobre papel, entre 1831 y 1880. El convento de Santa Lucв”ңВЎa fue ocupado por los cistercienses en 1563. En 1965, la comunidad monв”ңГӯstica que lo habitaba lo vendiв”ңв”Ӯ para su derribo. Fuente: "Viaje artв”ңВЎstico por Aragв”ңв”Ӯn de Valentв”ңВЎn Carderera", Josв”ңВ® Marв”ңВЎa Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaciв”ңв”Ӯn Lв”ңГӯzaro Galdiano, 2013.', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65822300, -0.89083800, '0101000020E6100000EC1681B1BE81ECBFCD3CB9A640D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15105691832.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15105691832.webp', 'https://www.flickr.com/photos/zaragozaantigua/15105691832/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21265, 'Puerta Sancho 1907', 'Postal. "Colecciв”ңв”Ӯn Patria y Fe nв”ңв•‘m. 25, Zaragoza 1908 - Centenario de los Sitios", 1907. "Pocos aв”ңв–’os ha, destruida. Fue el lugar donde tanto se distinguiв”ңв”Ӯ Casta в”ңГјlvarez, y donde el bizarro D. Mariano Renovales sostuvo y rechazв”ңв”Ӯ constantemente los ataque a los franceses." Vista del lateral de la calle de Santa Lucв”ңВЎa de la iglesia del convento de las Fecetas. La puerta se derribв”ңв”Ӯ en 1868. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65844800, -0.89186400, '0101000020E6100000105A0F5F268AECBFED0E290648D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20771128705.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20771128705.webp', 'https://www.flickr.com/photos/zaragozaantigua/20771128705/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22198, 'Santa Lucв”ңВЎa 1951', 'Luminosa imagen capturada al comienzo de la calle de Santa Lucв”ңВЎa, enfocando hacia el este. A la izquierda, muro perimetral de la antigua Alcoholera Agrв”ңВЎcola del Pilar, luego Azucarera, de la que destaca su descomunal chimenea. Sobre el firme, tendido tranviario de la lв”ңВЎnea 7, o del Ayuntamiento. Al fondo, silueta del edificio del Ayuntamiento, en la plaza de Santo Domingo. A la derecha, e inmediata, fachada del convento de las Fecetas. Al fondo, entre el ramaje, la residual espadaв”ңв–’a como tenue recuerdo de la que fue gran torre mudв”ңВ®jar del antiguo convento de Santa Lucв”ңВЎa, que aв”ңв•‘n perduraba. Fuente visual: foto Juan Mora Insa, en AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65839800, -0.89130700, '0101000020E61000009544F6419685ECBF3BE0BA6246D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33534953566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33534953566.webp', 'https://www.flickr.com/photos/zaragozaantigua/33534953566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23007, 'Calle de Santa Lucв”ңВЎa 1997', 'Imagen del antiguo claustro del barroco convento de las carmelitas descalzas de Santa Teresa de Jesв”ңв•‘s, o Fecetas, capturada probablemente antes del inicio de las obras de restauraciв”ңв”Ӯn acometidas por el Gobierno de Aragв”ңв”Ӯn a finales del pasado siglo XX. Tras el derribo del sureв”ңв–’o cuerpo del original claustro de planta cuadrada, perpetrado durante la reurbanizaciв”ңв”Ӯn a la carta de la zona al objeto de dar acceso rodado y peatonal al inmediato inmueble del nв”¬в•‘ 11 de la calle de Santa Lucв”ңВЎa, y peatonal a los nв”ңв•‘meros 86-88 del paseo de Marв”ңВЎa Agustв”ңВЎn, quedaba este resto en forma de "U" que ha llegado hasta nuestros dв”ңВЎas. A la original altura de dos pisos se habв”ңВЎa aв”ңв–’adido un tercer piso con fines utilitarios de carв”ңГӯcter habitacional que serв”ңВЎa eliminado durante la restauraciв”ңв”Ӯn. En el centro del patio, pozo bajo el que se abrв”ңВЎa un aljibe o reservorio de agua. Fuente visual: AMZ', 1997, 1997, 1997, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65819000, -0.89191900, '0101000020E6100000F3CAF5B6998AECBFF146E6913FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28009934467.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28009934467.webp', 'https://www.flickr.com/photos/zaragozaantigua/28009934467/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23270, 'Puerta de Sancho 1808', 'Baterв”ңВЎa de la Puerta de Sancho, grabado, Gв”ңГӯlvez y Brambila, 1812. Trata de reproducir la defensa ante el ataque francв”ңВ®s del 2 de julio de 1808, a la Puerta de Sancho, defendida por los caв”ңв–’ones, la Puerta del Portillo (la iglesia del centro), y el convento de los Agustinos (al fondo a la izquierda) extramuros, cerca del Cuartel de caballerв”ңВЎa de El Cid. Mariano Renovales resiste en la Puerta de Sancho; Santiago Sas, en el Convento; en el Portillo aparece una tal Agustina Zaragoza (Agustina de Aragв”ңв”Ӯn). Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65835300, -0.89148300, '0101000020E610000038143E5B0787ECBF9B1C3EE944D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15253073071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15253073071.webp', 'https://www.flickr.com/photos/zaragozaantigua/15253073071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24126, 'La Almozara 1916', 'Fotograma de un reportaje dedicado a la fiesta del в”ңГӯrbol celebrada el 1 de abril de ese aв”ңв–’o en los viveros del Ayuntamiento sitos en el soto de La Almozara junto al Puente del Ferrocarril y protagonizada por cerca de 400 niв”ңв–’as de las escuelas municipales de la ciudad (Armas, Arrabal, Buen Pastor, Casablanca, Castillo, Graneros, Montemolв”ңВЎn, Torrero), asв”ңВЎ como de la graduada de la Normal y del Hospicio. Escoltadas por sus maestras, acudieron al lugar en comitiva desde la Casa Consistorial acompaв”ңв–’adas de las bandas de mв”ңв•‘sica del regimiento del Infante y del Hospicio provincial, de una dotaciв”ңв”Ӯn de la guardia urbana y de varios representantes municipales. Tras la plantaciв”ңв”Ӯn entonaron el "himno del в”ңГӯrbol" y fueron obsequiadas con una apetitosa merienda. En la imagen, vista de una de las parcelas destinadas a este evento, con varias niв”ңв–’as posando junto a los в”ңГӯrboles a raв”ңВЎz desnuda ya plantados en los hoyos excavados al efecto. Un par de dв”ңВЎas antes tuvo lugar otra fiesta del в”ңГӯrbol, protagonizada en este caso por los niв”ңв–’os de las escuelas municipales.', 1916, 1916, 1916, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65999200, -0.89083600, '0101000020E6100000BE2EC37FBA81ECBF92CF2B9E7AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54707306493.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54707306493.webp', 'https://www.flickr.com/photos/zaragozaantigua/54707306493/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24191, 'Paso a nivel La Almozara c.1980', 'Vista del paso a nivel de La Almozara hacia 1980, en el entorno de la actual plaza de Europa. Fuente: www.facebook.com/photo.php?fbid=1486032418364255&set=...', 1980, 1980, 1980, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65971000, -0.89151300, '0101000020E6100000E2AE5E454687ECBF0D6C956071D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21268567306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21268567306.webp', 'https://www.flickr.com/photos/zaragozaantigua/21268567306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24346, 'Las Fecetas 1975', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Junio 1975. Imagen del estado del Convento de Carmelitas Descalzas de Santa Teresa, en el nв”ңв•‘mero 5 de la calle Santa Lucв”ңВЎa. Es mв”ңГӯs conocido como Г”ГҮВЈLas FecetasГ”ГҮГҳ derivaciв”ңв”Ӯn del apellido del notario zaragozano Don Diego Fecet, que en 1623 obtuvo la bula papal para su fundaciв”ңв”Ӯn. De factura barroca, en ladrillo, este complejo conventual era lugar de acogimiento para las hijas de cargos pв”ңв•‘blicos de Aragв”ңв”Ӯn que deseasen dedicarse a la vida religiosa. Se conserva la iglesia, y restos de un claustro de dos pisos. En la imagen, continuando por la calle de Santa Lucв”ңВЎa vemos las barreras levantadas del Paso a Nivel del Ferrocarril de la Quв”ңВЎmica, cuyas instalaciones quedan al fondo.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65825200, -0.89155000, '0101000020E61000002BF697DD9387ECBF6743FE9941D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14708827460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14708827460.webp', 'https://www.flickr.com/photos/zaragozaantigua/14708827460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24401, 'Calle Santa Lucв”ңВЎa 1922', 'Dibujo de Dв”ңВЎaz Domв”ңВЎnguez del emboque de la calle de Santa Lucв”ңВЎa con el final del paseo de Marв”ңВЎa Agustв”ңВЎn, donde se habв”ңВЎa ubicado la Puerta de Sancho. A la derecha, el convento de las Fecetas. Fuente visual: Revista La Cadiera.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65844800, -0.89186400, '0101000020E6100000105A0F5F268AECBFED0E290648D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29324531788.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29324531788.webp', 'https://www.flickr.com/photos/zaragozaantigua/29324531788/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24413, 'Las Fecetas 1987', 'Foto: Tomв”ңГӯs Mora Ruata. Vista de la iglesia del convento de las Fecetas, con la calle de Santa Lucв”ңВЎa a la derecha. Al fondo, plaza de Europa y barrio de La Almozara.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65833400, -0.89157500, '0101000020E610000064CC5D4BC887ECBF25ECDB4944D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32647111864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32647111864.webp', 'https://www.flickr.com/photos/zaragozaantigua/32647111864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24415, 'Calle Santa Lucв”ңВЎa 1975', 'Imagen de la fachada e ingreso al antiguo convento de las madres Carmelitas Descalzas de Santa Teresa, o Fecetas, sito en el nв”ңв•‘mero 5 de la calle Santa Lucв”ңВЎa. De factura barroca, en ladrillo, este gran complejo conventual hoy perdura de forma parcial (iglesia, y restos de un claustro de dos pisos), y en un entorno brutalmente descontextualizado. Sobre el firme, apenas perceptible, el antiguo trazado tranviario de la lв”ңВЎnea 7, o Ayuntamiento. Al fondo, el paseo de Marв”ңВЎa Agustв”ңВЎn. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65833400, -0.89157500, '0101000020E610000064CC5D4BC887ECBF25ECDB4944D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32916493626.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32916493626.webp', 'https://www.flickr.com/photos/zaragozaantigua/32916493626/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24419, 'Calle de Santa Lucв”ңВЎa 1977', 'Imagen luminosa de los restos del antiguo convento barroco de las MM. Carmelitas Descalzas de Santa Teresa bajo el perenne asedio de modernas construcciones habitacionales de la zona, en una de las muestras mв”ңГӯs memorables del urbanismo a la carta de los primeros aв”ңв–’os setenta del pasado siglo. Para mejor aprovechamiento del viario, ademв”ңГӯs, nada como el aparcamiento en baterв”ңВЎa, por donde antaв”ңв–’o transitaran tranvв”ңВЎas de la lв”ңВЎnea del Ayuntamiento. Fuente visual: revista "Aragв”ңв”Ӯn turв”ңВЎstico y monumental", SIPA.', 1977, 1977, 1977, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65833400, -0.89157500, '0101000020E610000064CC5D4BC887ECBF25ECDB4944D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34825055345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34825055345.webp', 'https://www.flickr.com/photos/zaragozaantigua/34825055345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25530, 'Puente de la Almozara 1934', 'Foto: Miguel Marв”ңВЎn Chivite. El 16 de julio de 1932, una bomba explotв”ңв”Ӯ en el tercer apoyo del puente de la Almozara sobre el Ebro. Cuando el ferrocarril lo atravesв”ңв”Ӯ despuв”ңВ®s, se comprobв”ңв”Ӯ que oscilaba ostensiblemente. Se comprobв”ңв”Ӯ que la cimentaciв”ңв”Ӯn de ese apoyo estaba descalzado, pero debido no a la explosiв”ңв”Ӯn de la bomba sino a la fuerte avenida del Ebro de marzo de 1930. Las obras de reparaciв”ңв”Ӯn corrieron a cargo de la empresa Agroman, que en esos momentos se hallaba consolidando el templo del Pilar. En la imagen, aspecto parcial de las obras en el Puente, en 1934. Al fondo, la margen izquierda. Fuente: Heraldo de Aragв”ңв”Ӯn.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.66109400, -0.89059500, '0101000020E61000005665DF15C17FECBF79CA6ABA9ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15060180447.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15060180447.webp', 'https://www.flickr.com/photos/zaragozaantigua/15060180447/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25830, 'Puerta Sancho 1861', '"Puerta del rey Don Sancho", Antonio Callaved, 2011. Junto al convento de las Fecetas, en la actual calle de santa Lucв”ңВЎa junto a la plaza de Europa, se levantaba esta modesta puerta, que fue derribada en 1868. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1861, 1861, 1861, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65844800, -0.89186400, '0101000020E6100000105A0F5F268AECBFED0E290648D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15255871276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15255871276.webp', 'https://www.flickr.com/photos/zaragozaantigua/15255871276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21268, 'Calle Azoque 1907', 'Joan Rubiв”ңв”Ӯ i Bellver era arquitecto y declarado discв”ңВЎpulo de Gaudв”ңВЎ, y la mayor parte de su obra estв”ңГӯ radicada en Barcelona. En 1907, mientras diseв”ңв–’aba grandes viviendas para la burguesв”ңВЎa barcelonesa del Ensanche, se ocupв”ңв”Ӯ tambiв”ңВ®n de un pequeв”ңв–’o encargo zaragozano: el diseв”ңв–’o de la "Farmacia Nueva" de Ramв”ңв”Ӯn Puig Mas, en Azoque 4, un local para el que compuso la mejor fachada comercial modernista de la ciudad, conjugando de forma eclв”ңВ®ctica el gв”ңв”Ӯtico y el modernismo mediante ladrillos, hierro, y cristal. Resultв”ңв”Ӯ ser una muestra de arquitectura efв”ңВЎmera, pues al poco tiempo hubo una importante actuaciв”ңв”Ӯn en la zona que afectв”ңв”Ӯ al local: el ensanche, alineaciв”ңв”Ӯn y prolongaciв”ңв”Ӯn de la calle del Portillo. Fue trasladada a otro local de planta inverosв”ңВЎmil, entre la calle del Coso nв”¬в•‘ 6 y Azoque nв”¬в•‘ 7, con entrada principal por el Coso. Era una de las farmacias mв”ңГӯs importantes de la ciudad. En 1930, Francisco Albiв”ңв–’ana habrв”ңВЎa participado en el diseв”ңв–’o del nuevo local, unos pocos aв”ңв–’os antes de idear el inmediato edificio "Ciudad de Londres". En la imagen, dibujo de la proyectada fachada exterior de la farmacia, para su ubicaciв”ңв”Ӯn en la antigua calle Azoque, 4. Fuente visual: Jesв”ңв•‘s Martв”ңВЎnez Verв”ңв”Ӯn, "Arquitectura aragonesa: 1885-1920"', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65382900, -0.88419400, '0101000020E6100000B9382A37514BECBF94162EABB0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21415459294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21415459294.webp', 'https://www.flickr.com/photos/zaragozaantigua/21415459294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21407, 'Escuelas Pв”ңВЎas c.1918', 'Imagen de la Fototipia Thomas, titulada "Clase de Instrucciв”ңв”Ӯn Militar", dentro de la serie dedicada al colegio de las Escuelas Pв”ңВЎas. Aunque la creciente preocupaciв”ңв”Ӯn por el enemigo interior aumentaba, la enseв”ңв–’anza de la religiв”ңв”Ӯn y de la instrucciв”ңв”Ӯn militar seguв”ңВЎan apuntalando el credo pedagв”ңв”Ӯgico tradicionalista, que mantenв”ңВЎa la ensoв”ңв–’aciв”ңв”Ӯn de pretв”ңВ®ritas grandezas imperiales, ahora pв”ңГӯlidamente reflejadas en la gestiв”ңв”Ӯn de residuales colonias africanas. En la imagen, marcial posado de escolares en el cuadrado y colegial patio de La Orden de los Clв”ңВ®rigos Regulares pobres de la Madre de Dios de las Escuelas Pв”ңВЎas. El instructor militar, atento a la formaciв”ңв”Ӯn. Fuente: www.todocoleccion.net/', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65455100, -0.88483800, '0101000020E6100000EE4108C89750ECBF3448C153C8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25628095411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25628095411.webp', 'https://www.flickr.com/photos/zaragozaantigua/25628095411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21417, 'Escuelas Pв”ңВЎas 1918', 'Postal. Fototipia Thomas. Entrada principal del colegio e internado de las Escuelas Pв”ңВЎas de los padres escolapios (1735), en la calle Nueva del Portillo, luego Conde de Aranda. Las torretas, producto de la remodelaciв”ңв”Ӯn de la fachada acometida por Miguel в”ңГјngel Navarro Pв”ңВ®rez, serв”ңГӯn eliminadas en la reforma de 1961. Fuente: www.todocoleccion.net', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65449100, -0.88515100, '0101000020E6100000BCB1A0302853ECBF5F43705CC6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30833019846.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30833019846.webp', 'https://www.flickr.com/photos/zaragozaantigua/30833019846/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21430, 'Calle del Portillo 1918', 'Imagen de la nueva gran fachada principal del colegio e internado de las Escuelas Pв”ңВЎas de los padres escolapios (fundados en 1735), producto de la remodelaciв”ңв”Ӯn acometida por Miguel в”ңГјngel Navarro Pв”ңВ®rez. Algunos de sus elementos serв”ңГӯn modificados o suprimidos en una reforma posterior (1961). La calle Nueva del Portillo, tambiв”ңВ®n se encuentra en obras de ampliaciв”ңв”Ӯn y ensanchamiento. Fuente visual: postal de la serie "Colegio de las Escuelas Pв”ңВЎas" de Zaragoza, titulada "Fachada principal del Internado", editada por Fototipia Thomas (Barcelona), en www.ebay.es/', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65449100, -0.88515100, '0101000020E6100000BCB1A0302853ECBF5F43705CC6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34382016532.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34382016532.webp', 'https://www.flickr.com/photos/zaragozaantigua/34382016532/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21726, 'Escuelas Pв”ңВЎas 1936', 'Foto: Colecciв”ңв”Ӯn familia Campos. Grupo de voluntarios falangistas posando ante la puerta del colegio de las Escuelas Pв”ңВЎas de Zaragoza en 1936. Fuente: www.facebook.com/photo.php?fbid=828143143915970&set=g...', 1936, 1936, 1936, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65449100, -0.88515100, '0101000020E6100000BCB1A0302853ECBF5F43705CC6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20707859616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20707859616.webp', 'https://www.flickr.com/photos/zaragozaantigua/20707859616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21775, 'Colegio Escolapios 1932', 'Calles del Conde de Aranda y de las Escuelas Pв”ңВЎas. Enfrente, el colegio de los Escolapios. Fuente visual: Foto Conrado Barlв”ңВ®s, donada por Daniel Barlв”ңВ®s y digitalizada por Josв”ңВ® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65421900, -0.88440000, '0101000020E610000005A3923A014DECBFFEB5BC72BDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22880340899.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22880340899.webp', 'https://www.flickr.com/photos/zaragozaantigua/22880340899/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21828, 'Gigantes y Cabezudos 1931', 'Imagen capturada desde cierta altura, posiblemente en el nв”¬в•‘ 8 del Coso alto, de la comparsa de Gigantes y Cabezudos en un posado conjunto durante las fiestas mayores de Zaragoza, al que se suman gozosos pardales y tancredos conscientes del inmortal momento. Figuran las gigantonas representaciones del rey Alfonso I (antes, Jaime I) y Doв”ңв–’a Urraca (antes, una de las mujeres de Jaime I), el Duque y la Duquesa de Villahermosa, el Chino y la Negra, Don Quijote y Dulcinea, y las de los mв”ңГӯs menudos Tuerto, Verrugв”ңв”Ӯn, Morico, Robaculeros, Boticario, Torero, Forana, y Forano. Tras ellos, el palacio de la Audiencia, y el arranque de la calle de Cerdв”ңГӯn. Fuente visual: foto Marв”ңВЎn Chivite, en diario "Ahora".', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65412600, -0.88388300, '0101000020E610000018B14F00C548ECBF4DBB9866BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32680328502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32680328502.webp', 'https://www.flickr.com/photos/zaragozaantigua/32680328502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22103, 'Calle del General Franco 1951', 'La calle del General Franco, luego del Conde de Aranda, en la confluencia hacia la derecha con la calle de las Escuelas Pв”ңВЎas, en una vista centrada en el soleado tramo que comienza en el colegio de los Escolapios. Sobre la calzada se cruzan una unidad tranviaria de la lв”ңВЎnea 2. Madrid y una composiciв”ңв”Ӯn motor+remolque de la lв”ңВЎnea 3. Delicias. Fuente visual: Los tranvв”ңВЎas de Zaragoza, Javier Peв”ңв–’a Gonzalvo, Josв”ңВ® Marв”ңВЎa Valero Suв”ңГӯrez, Zaragoza: DPZ, 1985.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65422700, -0.88460400, '0101000020E610000024253D0CAD4EECBF8194D8B5BDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20683173996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20683173996.webp', 'https://www.flickr.com/photos/zaragozaantigua/20683173996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22358, 'Calles Escuelas Pв”ңВЎas y Cerdв”ңГӯn c.1966', 'Toma del chaflв”ңГӯn de la manzana de separaciв”ңв”Ӯn entre las calles Escuelas Pв”ңВЎas y Cerdв”ңГӯn (derecha). Fuente: www.skyscrapercity.com/', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65410800, -0.88408800, '0101000020E61000004E27D9EA724AECBFA7069ACFB9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20716812911.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20716812911.webp', 'https://www.flickr.com/photos/zaragozaantigua/20716812911/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22400, 'Calle San Martв”ңВЎn 1961', 'Cartelera cinematogrв”ңГӯfica zaragozana exhibida en el lateral del cine Victoria, correspondiente a la calle de San Martв”ңВЎn. Al fondo, calle de Ramв”ңв”Ӯn Pignatelli. Fuente: www.rafaelcastillejo.com', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65389800, -0.88524700, '0101000020E6100000433A3C84F153ECBFBC75FEEDB2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23426289780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23426289780.webp', 'https://www.flickr.com/photos/zaragozaantigua/23426289780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22472, 'Escolapios 1962', 'Alumnos del colegio de las Escuelas Pв”ңВЎas (al fondo) desfilan enfilando el Coso Alto. Detrв”ңГӯs, los arranques de las calles de las Escuelas Pв”ңВЎas y de Cerdв”ңГӯn. Fuente: www.facebook.com/photo.php?fbid=1374968819192406&set=...', 1962, 1962, 1962, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65405700, -0.88405800, '0101000020E6100000A48CB800344AECBF255CC823B8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33472703716.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33472703716.webp', 'https://www.flickr.com/photos/zaragozaantigua/33472703716/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22532, 'Calle Cerdв”ңГӯn 1976', 'Luis Mompel/Heraldo de Aragв”ңв”Ӯn. Manzana que, del Coso (en la foto) al Mercado Central estuvo en pie hasta su derribo en 1977.', 1976, 1976, 1976, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65407400, -0.88407000, '0101000020E6100000B5FD2B2B4D4AECBFFB9463B2B8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14730793688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14730793688.webp', 'https://www.flickr.com/photos/zaragozaantigua/14730793688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22785, 'Calle del General Franco 1979', 'Imagen centrada en el tradicionalista rв”ңв”Ӯtulo de la calle del General Franco adosado a la fachada del colegio de los PP. Escolapios. Esta calle, antigua del Portillo, habв”ңВЎa sido redenominada del Conde de Aranda en los aв”ңв–’os veinte del pasado siglo XX. En 1937 el Consistorio faccioso le cambiв”ңв”Ӯ la denominaciв”ңв”Ӯn por la de General Franco. En 1979, tras la recuperaciв”ңв”Ӯn de la democracia municipal, el nuevo ayuntamiento con mayorв”ңВЎa de izquierdas (PSOE, PCE, PTA) decidiв”ңв”Ӯ modificar del nombre de algunos de los 102 viales de la ciudad que tras el 17-18 de julio de 1936 habв”ңВЎan sido cambiados por el nuevo rв”ңВ®gimen. Asв”ңВЎ, la calle del General Franco recuperв”ңв”Ӯ su previa denominaciв”ңв”Ӯn (Conde de Aranda), al igual que la calle del Requetв”ңВ® Aragonв”ңВ®s (5 de Marzo). En el caso de la plaza de Josв”ңВ® Antonio tambiв”ңВ®n estaba previsto que recuperara su denominaciв”ңв”Ӯn anterior (Castelar), si bien finalmente se quedarв”ңВЎa con una nueva: Los Sitios. El paseo de Calvo Sotelo, que fuera Avenida de Pablo Iglesias, hubiera tenido que ser la Gran Vв”ңВЎa de la Constituciв”ңв”Ӯn, y se quedв”ңв”Ӯ en Gran Vв”ңВЎa a secas. A lo largo de ese aв”ңв–’o de 1979 otros nombres se aв”ңв–’adieron a la lista (Marina Moreno, General Millв”ңГӯn Astray, General Mola, Requetв”ңВ® Navarro, Vieja Guardia ...) En noviembre de 2017 aв”ңв•‘n perduran en la ciudad algunos viales que homenajean a quienes se alzaron en armas contra la democracia espaв”ңв–’ola republicana en 1936. Fuente visual: Andalв”ңГӯn, periв”ңв”Ӯdico semanal aragonв”ңВ®s, 1979.', 1979, 1979, 1979, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65439000, -0.88476300, '0101000020E610000044BFB67EFA4FECBF2B6A300DC3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38413110772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38413110772.webp', 'https://www.flickr.com/photos/zaragozaantigua/38413110772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22791, 'Coso Alto 1978', 'Imagen capturada desde el despejado ensanche resultante del derribo de la manzana de viviendas entre las antiguas calles de las Escuelas Pв”ңВЎas y Cerdв”ңГӯn, centrada en el emboque de la calle de Azoque, al fondo. Chaflanero, perduraba el edificio "La ciudad de Londres", diseв”ңв–’ado por Albiв”ңв–’ana, aunque los inmediatos andamios de derribo del nв”¬в•‘ 6 anunciaban la pronta prolongaciв”ңв”Ӯn quirв”ңв•‘rgica de la Vв”ңВЎa Imperial por esa zona. Hacia la derecha, principio de la calle del General Franco. Hacia la izquierda, arranque del tramo alto del Coso. Tras el ingreso por la calle Azoque, perduraba la antigua plaza de Luis Santв”ңГӯngel, luego desaparecida. En primer plano, notable concentraciв”ңв”Ӯn de vehв”ңВЎculos aparcados al raso. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65405700, -0.88405800, '0101000020E6100000A48CB800344AECBF255CC823B8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41192728892.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41192728892.webp', 'https://www.flickr.com/photos/zaragozaantigua/41192728892/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23047, 'Av. de Cв”ңВ®sar Augusto 1991', 'Imagen capturada posiblemente desde la altura del inmueble del nв”¬в•‘ 42 de la avenida de Cв”ңВ®sar Augusto, y centrada en la nueva iluminaciв”ңв”Ӯn nocturna mediante farolas "de corte antiguo" del tramo de esta vв”ңВЎa reciв”ңВ®n remodelado con motivo de la construcciв”ңв”Ӯn de un aparcamiento subterrв”ңГӯneo con capacidad para 349 vehв”ңВЎculos, y cuya entrada y salida en esta escena todavв”ңВЎa estв”ңГӯn cerradas con vallas de obra. El importe total de esta intervenciв”ңв”Ӯn, unos 402 millones de pesetas, fue cubierto por la empresa Estacionamientos El Pilar, S.A. (EPSA), concesionaria de la explotaciв”ңв”Ӯn comercial tanto de este aparcamiento como los de la plaza del Pilar y de los Juzgados, cuyas instalaciones pasarв”ңГӯn a propiedad municipal en el aв”ңв–’o 2041.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65439600, -0.88421700, '0101000020E6100000C4263273814BECBF0D51853FC3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50437258566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50437258566.webp', 'https://www.flickr.com/photos/zaragozaantigua/50437258566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23512, 'Coso Alto 1938', 'Otra de las interesantes imв”ңГӯgenes capturadas por un miembro de la "Legiв”ңв”Ӯn Condor", el contingente de la Luftwaffe enviado para echar una mano a sus camaradas espaв”ңв–’oles nacionalistas, durante su estancia en la ciudad a finales de los aв”ңв–’os 30. La vista parece realizada desde la terraza del acuartelamiento de estos alemanes voladores (colegio de los Escolapios). Inmediata, la que fuera antigua plaza de Estrв”ңВ®vedes, o confluencia de la Cedacerв”ңВЎa, Albarderв”ңВЎa, Azoque, y Coso. En la imagen, esas dos primeras calles eran ya (tiempo ha) Escuelas Pв”ңВЎas, y Cerdв”ңГӯn, a la izquierda. A la derecha, primeros nв”ңв•‘meros pares del Coso, con un pedazo del edificio "Ciudad de Londres", y la fachada de la "Farmacia Nueva" de Ramв”ңв”Ӯn Puig, recayente a esta calle.', 1938, 1938, 1938, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65410800, -0.88408800, '0101000020E61000004E27D9EA724AECBFA7069ACFB9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24524440199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24524440199.webp', 'https://www.flickr.com/photos/zaragozaantigua/24524440199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23525, 'Calle de Cerdв”ңГӯn 1932', 'Imagen capturada en el arranque del Coso Alto y centrada en la manzana de viviendas entre las calles de las Escuelas Pв”ңВЎas (a la izquierda) y la de Cerdв”ңГӯn (a la derecha), en cuyo nв”¬в•‘ 1 estaba radicado el Hotel Hispano Francв”ңВ®s, y en sus bajos comerciales el almacв”ңВ®n de comestibles de Emв”ңВ®rito Gambв”ңв”Ӯn.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65430000, -0.88421700, '0101000020E6100000C4263273814BECBFEBE2361AC0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49918087943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49918087943.webp', 'https://www.flickr.com/photos/zaragozaantigua/49918087943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24076, 'Calle General Franco 1960', 'Imagen capturada en el interior del cinematв”ңв”Ӯgrafo Victoria tras la reforma proyectada por los arquitectos Josв”ңВ® de Yarza Garcв”ңВЎa y Alejandro Allв”ңГӯnegui Fв”ңВ®lez. Esta sala estuvo funcional como cine entre 1943 y 1985. Fuente visual: arch. J. de Yarza', 1960, 1960, 1960, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65422200, -0.88532000, '0101000020E6100000BFD4CF9B8A54ECBF6F29E78BBDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38216863761.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38216863761.webp', 'https://www.flickr.com/photos/zaragozaantigua/38216863761/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25152, 'Calle San Ildefonso aв”ңв–’os 30', 'Acuarela de Ambrosio Ruste, representando la calle de San Ildefonso, con la iglesia homв”ңв”Ӯnima (luego de Santiago el Mayor) al fondo a la derecha. Fuente: Lв”ңГӯminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65297400, -0.88497000, '0101000020E6100000A81DFE9AAC51ECBFB491EBA694D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31627091013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31627091013.webp', 'https://www.flickr.com/photos/zaragozaantigua/31627091013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25700, 'Arco de San Ildefonso 1925', 'Imagen del Arco de San Ildefonso, capturado desde la calle de San Ildefonso. Pasado el arco, y a la derecha, se abre la plaza de San Lamberto. Al fondo, la calle de Diego Castillo conduce a la calle Ramв”ңв”Ӯn y Cajal, y a la plaza de la Victoria. Este arco formaba parte del grandioso conjunto barroco del convento de San Ildefonso de los PP. Dominicos, construido entre 1625 y 1695. La enorme iglesia conventual estaba flanqueada por el arranque, sin culminar, de dos poderosas torres de planta cuadrangular. El acceso a la torre de la derecha se habв”ңВЎa horadado y convertido en arco de medio punto y bв”ңв”Ӯveda de caв”ңв–’в”ңв”Ӯn, para comunicaciв”ңв”Ӯn viaria. Fuente visual: Lucien Roisin, AMZ.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65277100, -0.88499900, '0101000020E61000003BC43F6CE951ECBF7C6308008ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21370663624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21370663624.webp', 'https://www.flickr.com/photos/zaragozaantigua/21370663624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25815, 'Calle del General Franco c.1955', 'Tranvв”ңВЎa de la lв”ңВЎnea 5 "Venecia-Delicicas", frente al colegio de Escuelas Pв”ңВЎas. Fuente: www.facebook.com/photo.php?fbid=518027164989911&set=g...', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65410500, -0.88427800, '0101000020E61000002F505260014CECBF36936FB6B9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14738231119.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14738231119.webp', 'https://www.flickr.com/photos/zaragozaantigua/14738231119/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25852, 'Calle del General Franco c.1956', 'Imagen capturada desde cierta altura y centrada en el primer tramo de los nв”ңв•‘meros pares de la calle del General Franco, donde destaca la gran fachada del colegio de los Escolapios, de la que destacan las dos originales torrecillas que culminaban el ingreso principal al colegio, y el torreв”ңв”Ӯn que albergв”ңв”Ӯ un observatorio meteorolв”ңв”Ӯgico. Una reforma posterior eliminarв”ңВЎa estos remates. En el centro de la animada escena callejera, una composiciв”ңв”Ӯn tranviaria de la lв”ңВЎnea 5. Venecia-Delicias, posiblemente compuesta por el coche motor nв”¬в•‘ 82 y el remolque nв”¬в•‘ 78, encaminado hacia el Coso Alto. Otra composiciв”ңв”Ӯn de esta lв”ңВЎnea, al fondo, se dirige hacia el barrio de Las Delicias.', 1956, 1956, 1956, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65430000, -0.88488200, '0101000020E6100000D6355A0EF450ECBFEBE2361AC0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49889078638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49889078638.webp', 'https://www.flickr.com/photos/zaragozaantigua/49889078638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21046, 'Calle de la Misericordia 1867', 'Dibujo incluido en el anteproyecto para la "Academia de Yngenieros del egercito", con detalle de la fachada principal del edificio recayente a la calle de la Misericordia, donde estuviera la antigua fв”ңГӯbrica de salitres vecina del cuartel de Convalecientes. Este proyecto no pasв”ңв”Ӯ de las musas al teatro, y el solar de la antigua fв”ңГӯbrica de salitres fue incorporado al cuartel de Convalecientes, luego cuartel de ingenieros de Sangenв”ңВЎs.', 1867, 1867, 1867, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65334600, -0.88914100, '0101000020E61000002C0C91D3D773ECBF787C7BD7A0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54224330883.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54224330883.webp', 'https://www.flickr.com/photos/zaragozaantigua/54224330883/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21175, 'Cuartel de Sangenis c.1890', 'Formaciones de caballerв”ңВЎa en el patio del cuartel de Sangenis. Al fondo, la Torre Nueva, la de San Felipe, el convento de la Victoria, la cв”ңв•‘pula de la iglesia de la Manteria y las traseras de la iglesia de San Ildefonso. Fuente: cesbor.blogspot.com.es/', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65340700, -0.88843500, '0101000020E610000075E5B33C0F6EECBF1EFD2FD7A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31250452330.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31250452330.webp', 'https://www.flickr.com/photos/zaragozaantigua/31250452330/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21299, 'Cuartel de Sangenis 1903', 'Foto: Nв”ңв•‘в”ңв–’ez. "Desfile del ganado y de la maniobra". Vista del patio del cuartel de Sangenis o de Pontoneros, con perspectiva al este de la cв”ңв•‘pula de la iglesia de la Manterв”ңВЎa, que se queda pequeв”ңв–’ita al lado del gran volumen de la de San Ildefonso. A la izquierda, convento de los Mв”ңВЎnimos de la Victoria. Fuente visual: Revista La Ilustraciв”ңв”Ӯn Espaв”ңв–’ola y Americana.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65343100, -0.88796300, '0101000020E610000087DBA161316AECBFA69883A0A3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32509288995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32509288995.webp', 'https://www.flickr.com/photos/zaragozaantigua/32509288995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21712, 'Convento de Santa Ana 1931', 'Casa-Noviciado de las Hermanas de la Caridad de Santa Ana, en 1931. Proyectado por Julio Bravo y Folch en 1905, se sitв”ңв•‘a en la calle de la Madre Rafols 13 de Zaragoza. Fuente: La Hormiga de Oro, noviembre de 1931.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65329700, -0.88934600, '0101000020E610000062821ABE8575ECBF97C9703C9FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18557530363.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18557530363.webp', 'https://www.flickr.com/photos/zaragozaantigua/18557530363/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23692, 'Avenida San Juan Bosco 1964', '1964. "Avda. S. Juan Bosco-Avda. Gв”ңв”Ӯmez Laguna". Familiar posado en un entorno agreste, porque este tramo de San Juan Bosco (desde Franco y Lв”ңв”Ӯpez) estaba aв”ңв•‘n por definir. Este era uno de los muchos "aquв”ңВЎ se acaba la ciudad". Al fondo, la mole del Edificio Torresol. A la derecha, algunas parcelas, y el nuevo edificio de la Escuela de Magisterio, ademв”ңГӯs de las enormes explanadas donde se instalaban las carpas de los circos y ferias en octubre. A la izquierda, tapando las parcelas de la Ciudad Jardв”ңВЎn, los recientes bloques de viviendas de la calle Milagrosa. Si el fotв”ңв”Ӯgrafo se hubiera dado la vuelta, hubiera sacado una interesante variedad de campos de cultivo que la ciudad estaba a punto de tragarse, y alguna parcela agrв”ңВЎcola por aв”ңв–’adidura. Como no lo hizo, pues nada.', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.64359800, -0.90478400, '0101000020E6100000C6353E93FDF3ECBFB0E2546B61D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14972351665.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14972351665.webp', 'https://www.flickr.com/photos/zaragozaantigua/14972351665/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21906, 'Cabalgata 1939', 'Imagen capturada durante la "cabalgata de los Reyes Magos" celebrada el 5 de enero de 1939, con salida en la plaza de Santo Domingo frente el Ayuntamiento y regreso al mismo punto tras un largo recorrido urbano donde en la plaza de Basilio Paraв”ңВЎso se les uniв”ңв”Ӯ el "Mago Nicolв”ңГӯs". En la imagen, la comitiva del rey Gaspar con sus pajes a caballo y criados a su servicio sale de los jardines del Hospicio Provincial entre los asilados del Hogar Pignatelli para seguir su itinerario por la calle de la Madre Rafols. En el pilar de la derecha, restos de un anuncio del "Aguinaldo del Combatiente", establecido en el territorio ocupado por el ejв”ңВ®rcito nacionalista a fin de recaudar recursos econв”ңв”Ӯmicos para llevar a los soldados y milicias, tanto combatientes, como hospitalizados, "el recuerdo de esta cristiana y tradicional fiesta de Navidad" que "les envв”ңВЎan los verdaderos espaв”ңв–’oles que con intensa emociв”ңв”Ӯn admiran su comportamiento heroico y estв”ңГӯn espiritualmente unidos con ellos en esta santa cruzada de la redenciв”ңв”Ӯn de Espaв”ңв–’a" (texto de la Orden publicada en el Boletв”ңВЎn Oficial del Estado el 9 de diciembre de 1936).', 1939, 1939, 1939, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65353900, -0.88974200, '0101000020E61000009015FC36C478ECBF8DD47B2AA7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51730770771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51730770771.webp', 'https://www.flickr.com/photos/zaragozaantigua/51730770771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22068, 'Iglesia de Santiago 1958', 'Iglesia de Santiago el Mayor. El mal estado permanente de la cв”ңв•‘pula obliga a una actuaciв”ңв”Ӯn. El arquitecto Borobia sube a la cв”ңв•‘pula para inspeccionar personalmente su estado, en unos andamios instalados para la ocasiв”ңв”Ӯn. Concluye que el estado es muy malo. Aв”ңв–’os despuв”ңВ®s, con proyecto y, con financiaciв”ңв”Ӯn, la cв”ңв•‘pula es restaurada integralmente, dв”ңГӯndole su aspecto actual. Fuente visual: "Una mirada a travв”ңВ®s de la arquitectura: Regino y Josв”ңВ® Borobio Ojeda", Daniel Estabв”ңВ®n Boldova, 2013.', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65279300, -0.88569900, '0101000020E61000006A32E36DA557ECBF640795B88ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15107841094.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15107841094.webp', 'https://www.flickr.com/photos/zaragozaantigua/15107841094/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22295, 'Cв”ңв•‘pula Santiago el Mayor 1965', 'Archivo Municipal. Gerardo Sancho. 13/07/1965 En el verano del aв”ңв–’o 1860, un rayo produjo el hundimiento de la cв”ңв•‘pula de la iglesia de Santiago el Mayor. Al poco tiempo, se hizo otra, aunque de bastante menos calidad. Casi un siglo despuв”ңВ®s, en 1958, Regino Borobio dirigiв”ңв”Ӯ una intervenciв”ңв”Ӯn de urgencia, dado su precario estado. En 1964 se iniciaron las obras para consolidar definitivamente la cв”ңв•‘pula, derribar del cupulв”ңВЎn existente y construir otro mв”ңГӯs ligero, ademв”ңГӯs de un arreglo general del techado. Estas obras duraron quince meses, fueron dirigidas tambiв”ңВ®n por el arquitecto Regino Borobio, y le dieron su actual aspecto.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65279300, -0.88569900, '0101000020E61000006A32E36DA557ECBF640795B88ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15409523374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15409523374.webp', 'https://www.flickr.com/photos/zaragozaantigua/15409523374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22341, 'Calle Pignatelli 1961', 'Imagen de la calle Pignatelli a la altura de los antiguos nв”ңв•‘meros 106-108 y 104. Al fondo, a la derecha, esta calle viene estrechica desde allв”ңГӯ en Azoque, cuando en el siglo XVIII era una sucesiв”ңв”Ӯn de calles denominadas ""Paja", "Dama", "Porterв”ңВЎa de las Victoria" (por el convento de ese nombre), "Cantarerв”ңВЎas", y "Eras del Campo del Toro", hasta llegar al Portillo. En el momento de capturar la imagen, desde la calle Mariano Cerezo, a la derecha, y hasta la plaza del Portillo, a la izquierda, habв”ңВЎa una continuidad determinada por la presencia, detrв”ңГӯs de estos edificios, del castrense "Parque de Artillerв”ңВЎa". Justo a nuestras espaldas queda el Hogar Pignatelli. Mв”ңГӯs tarde en el tiempo, cuando el "Parque de Artillerв”ңВЎa" sea comprado por el Ayuntamiento durante la "Operaciв”ңв”Ӯn Cuarteles", se abrirв”ңГӯ a la izquierda una continuidad de la calle Mayoral. En este punto concreto hoy estв”ңГӯ la denominada "Glorieta de Josв”ңВ® Aznв”ңГӯrez". De los edificios de la imagen (actuales 98-100 de la calle), que fueran producto de una remodelaciв”ңв”Ӯn llevada a cabo por Fernando de Yarza en 1902, hoy sв”ңв”Ӯlo queda la fachada, el resto es obra moderna. El antiguo 104, con su fachada de ladrillo, ha desaparecido, subsumido. Los bajos comerciales siguen vacantes. Fuente visual: amable aportaciв”ңв”Ӯn del Archivo personal de Pablo Valdв”ңВ®s.', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65425200, -0.88966700, '0101000020E6100000E692AAED2678ECBFDAAB8F87BED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20093917226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20093917226.webp', 'https://www.flickr.com/photos/zaragozaantigua/20093917226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22619, 'Hospital Provincial 1971', 'Hospital de Nuestra Seв”ңв–’ora de Gracia de Zaragoza, в”ңв”Ӯleo de Antonio Torres Clavero, 1971.', 1971, 1971, 1971, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65198200, -0.88671700, '0101000020E6100000D8D47954FC5FECBF53CA6B2574D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19374860350.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19374860350.webp', 'https://www.flickr.com/photos/zaragozaantigua/19374860350/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22659, 'Plaza de la Victoria 1970', 'Plaza de la Victoria en una escena capturada durante la tradicional celebraciв”ңв”Ӯn de San Juan de Dios, patrono del Cuerpo de Bomberos desde 1953. En esta plaza y a la derecha estaba ubicado el municipal Parque de Bomberos habilitado desde 1907 en el antiguo convento de Nuestra Seв”ңв–’ora de la Victoria de los Padres Mв”ңВЎnimos de San Francisco de Paula que, desamortizado en 1835, a finales de siglo fue reformado para dar cabida a un Parque de Bomberos y Depв”ңв”Ӯsito Municipal, ademв”ңГӯs de unas escuelas elementales de niв”ңв–’os y niв”ңв–’as, lo que supuso el derribo de la iglesia conventual. Al fondo y esquinera, junto a la banda de mв”ңв•‘sica, clarea la entrada a Frutos Solв”ңГӯns, S.A., en el nв”¬в•‘ 34 de la calle de Ramв”ңв”Ӯn y Cajal, antigua fв”ңГӯbrica de camas de Froilв”ңГӯn Solв”ңГӯns S.A. En primer tв”ңВ®rmino, el alcalde Mariano Horno Liria pasa revista a la formaciв”ңв”Ӯn de bomberos en uniforme de gala.', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65372300, -0.88605100, '0101000020E6100000AFD172A0875AECBF4ED2FC31ADD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22274483284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22274483284.webp', 'https://www.flickr.com/photos/zaragozaantigua/22274483284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22876, 'Plaza San Lamberto 1987', 'Una mirada a la plaza de San Lamberto que, junto con las inmediatas calles de las Doncellas y del Caballo, se configuraba como un tradicional espacio pecaminoso de la ciudad definido y conocido por el ejercicio de la prostituciв”ңв”Ӯn, ser zona de putas, o de mercadeo de carne humana y soberanв”ңВЎa de prostituidores. En los siglos XVI-XVII, el burdel o puterв”ңВЎa estuvo localizado muy cerca de aquв”ңВЎ y era pв”ңв•‘blico porque dependв”ңВЎa de las ordenanzas municipales. En el siglo XVIII la prostituciв”ңв”Ӯn fue consideraba un mal necesario, de ejercicio privado y oculto a la vista, y en el XIX fue reglamentada desde un punto de vista sanitario. En el siglo XX esta actividad se fue diversificando en algunas calles y zonas de la ciudad, incluso en una muy renombrada de la periferia. La de la imagen, capturada desde la altura de la torre norte de la iglesia de Santiago el Mayor sita sobre el Arco de San Ildefonso, perdura actualmente.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65304200, -0.88559000, '0101000020E6100000BB44F5D6C056ECBF0C7558E196D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15851642572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15851642572.webp', 'https://www.flickr.com/photos/zaragozaantigua/15851642572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22915, 'Calle de Pignatelli 1987', 'Imagen centrada en el nв”ңв•‘mero 60 de la calle de Ramв”ңв”Ӯn Pignatelli (antigua de Cantarerв”ңВЎas), edificio esquinero con la calle de Josв”ңВ® Zamoray (antigua del Candil, a la derecha). Fuente visual: AMZ.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65410200, -0.88744500, '0101000020E610000084F57F0EF365ECBFC51F459DB9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25065776518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25065776518.webp', 'https://www.flickr.com/photos/zaragozaantigua/25065776518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23174, 'Convento de los Mв”ңВЎnimos 2004', 'Obras de rehabilitaciв”ңв”Ӯn del antiguo convento franciscano de los Mв”ңВЎnimos de la Victoria (1576). Habв”ңВЎan comenzado en 1998 y se reanudaron en 2002 y 2004, proyectв”ңГӯndose abrir en 2007 como Museo del Fuego y de los Bomberos. Finalmente, la inauguraciв”ңв”Ӯn se produjo en 2012. La imagen muestra el patio del complejo. Fuente: Ayuntamiento de Zaragoza.', 2004, 2004, 2004, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65367700, -0.88672600, '0101000020E6100000A56950340F60ECBFDE921CB0ABD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33434444930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33434444930.webp', 'https://www.flickr.com/photos/zaragozaantigua/33434444930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23240, 'Arrabal islв”ңГӯmico 2002', 'En 2001 se hallaron restos arqueolв”ңв”Ӯgicos de un arrabal de Saraqusta de finales del siglo X-comienzos del XI, anterior a la conquista cristiana de la ciudad, en la zona del Campo del Toro protegida por la nueva muralla de rajola, posiblemente de funcionarios y trabajadores vinculados con el cercano palacio de la Aljaferв”ңВЎa. El hallazgo se realizв”ңв”Ӯ en el solar que ocupaban el patio y las dependencias anejas al antiguo Cuartel de Sangenis de Pontoneros e Ingenieros, que quedaron en pie tras los derribos de los aв”ңв–’os 80, como el edificio de viviendas para oficiales chaflanero con la calle Madre Rafols. En esta zona estaba previsto ubicar el Archivo Histв”ңв”Ӯrico de la Corona de Aragв”ңв”Ӯn, pues la titularidad del terreno habв”ңВЎa pasado a la DGA, mas los sondeos preceptivos para detectar posibles restos arqueolв”ңв”Ӯgicos antes de acometer los trabajos de construcciв”ңв”Ӯn del edificio del Archivo, dieron un imprevisto giro a las cosas. La incidencia de lo encontrado era tan elevada, que se desechв”ңв”Ӯ compatibilizar ambos asuntos: los restos se cubrieron para su conservaciв”ңв”Ӯn, el proyecto de Archivo se abandonв”ңв”Ӯ, y la parcela retornв”ңв”Ӯ al Patrimonio municipal, sin adjudicarse nuevos usos. En el aв”ңв–’o 2010 se realizв”ңв”Ӯ un anteproyecto para la promociв”ңв”Ӯn y gestiв”ңв”Ӯn en esta zona de un edificio de alojamientos para la comunidad universitaria en el marco del Г”ГҮВЈPlan Aragonв”ңВ®s para facilitar el acceso a la vivienda y rehabilitaciв”ңв”Ӯn 2009-2012Г”ГҮГҳ. En 2024 se terminaron las obras de la residencia de estudiantes, de capital privado, que incluyeron un anfiteatro sobre el lugar donde se hallan los restos arqueolв”ңв”Ӯgicos. En la imagen, al fondo a la derecha, la plaza de Josв”ңВ® Marв”ңВЎa Forquв”ңВ®. A la izquierda, la calle de la Palma. A la derecha, fuera de plano, el antiguo edificio de viviendas militares de la calle Madre Rafols. Fuente: Zaragoza Vivienda.', 2002, 2002, 2002, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65351500, -0.88873300, '0101000020E6100000EE073C308070ECBF04392861A6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19086318419.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19086318419.webp', 'https://www.flickr.com/photos/zaragozaantigua/19086318419/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23242, 'Calle de Escopeterв”ңВЎa 2008', 'En 2001 se hallaron restos arqueolв”ңв”Ӯgicos de un arrabal de Saraqusta de finales del siglo X-comienzos del XI, anterior a la conquista cristiana de la ciudad, en la zona del Campo del Toro protegida por la nueva muralla de rajola, posiblemente de residencia de funcionarios y trabajadores vinculados con el cercano palacio de la Aljaferв”ңВЎa. El hallazgo se realizв”ңв”Ӯ en el solar que ocupaban el patio y las dependencias anejas al antiguo cuartel de Sangenis de Pontoneros e Ingenieros, aв”ңв•‘n en pie tras los derribos de los aв”ңв–’os 80, como el edificio de viviendas para oficiales chaflanero con la calle de Madre Rafols. Aquв”ңВЎ estaba previsto ubicar el Archivo Histв”ңв”Ӯrico de la Corona de Aragв”ңв”Ӯn, pues la titularidad del terreno habв”ңВЎa pasado a la DGA, mas los sondeos arqueolв”ңв”Ӯgicos preceptivos dieron un imprevisto giro a las cosas. La incidencia de lo encontrado era tan elevada, que se desechв”ңв”Ӯ compatibilizar ambos asuntos: los restos se cubrieron para su conservaciв”ңв”Ӯn, el proyecto de Archivo se abandonв”ңв”Ӯ, y la parcela retornв”ңв”Ӯ al Patrimonio municipal, sin adjudicarse nuevos usos. En el aв”ңв–’o 2010 se realizв”ңв”Ӯ un anteproyecto para promover un edificio de alojamientos para la comunidad universitaria dentro del Г”ГҮВЈPlan Aragonв”ңВ®s para facilitar el acceso a la vivienda y rehabilitaciв”ңв”Ӯn 2009-2012Г”ГҮГҳ. Desde entonces, silencio. No hay banda. Inmediato a este solar, otro terreno, de propiedad privada, esquinero entre Escopeterв”ңВЎa y plaza Josв”ңВ® Marв”ңВЎa Forquв”ңВ®, fue tambiв”ңВ®n objeto de catas que sacaron a la luz otro buen pedazo del citado arrabal medieval. Como en el caso anterior, los particulares proyectos de construcciв”ңв”Ӯn previstos quedaron encallados, y los restos arqueolв”ңв”Ӯgicos de adobe y tapial, una vez finalizados los trabajos cientв”ңВЎficos, quedaron joreв”ңГӯndose al aire. Inmediatamente comenzв”ңв”Ӯ el natural proceso de colmataciв”ңв”Ӯn, a largo plazo, y el humano, mucho mв”ңГӯs acelerado y radical, consistente en la deposiciв”ңв”Ӯn de multidisciplinares residuos sв”ңв”Ӯlidos urbanos, orgв”ңГӯnicos, e inorgв”ңГӯnicos. Esto es lo que la imagen capt', 2008, 2008, 2008, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65378100, -0.88841000, '0101000020E61000003D0FEECEDA6DECBF83DF8618AFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24493212850.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24493212850.webp', 'https://www.flickr.com/photos/zaragozaantigua/24493212850/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23935, 'Calle de la Misericordia c.1896', 'Imagen capturada en los patios del cuartel de Sangenis del arma de ingenieros-pontoneros sito en la calle de la Misericordia durante la formaciв”ңв”Ӯn previa a la reglamentaria salida hacia una parada militar. Entre el material rodante destacan los componentes del moderno puente flotante danв”ңВ®s o Andersen. Al fondo, a la izquierda, la gran cв”ңв•‘pula del antiguo convento de San Ildefonso. A la derecha, instalaciones del Hospital Provincial. Fuente visual: www.bne.es/', 1896, 1896, 1896, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65326800, -0.88822800, '0101000020E610000012876C205D6CECBFFCC22B499ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25810873298.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25810873298.webp', 'https://www.flickr.com/photos/zaragozaantigua/25810873298/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24232, 'Calle de Ramв”ңв”Ӯn y Cajal 1955', 'Luminosa imagen de la local comparsa de cabezudos creada por Fв”ңВ®lix Oroz capturada en el patio del antiguo Convento de Nuestra Seв”ңв–’ora de la Victoria de los PP. Mв”ңВЎnimos de San Francisco de Paula, desde 1907 convertido en el Parque de Bomberos de la ciudad. De izquierda a derecha, los cabezudos Boticario, Torero, Tuerto, Morico, Forana, Forano, Robaculeros y Berrugв”ңв”Ӯn. Fuente visual: postal Darvi, en www.todocoleccion.net', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65367700, -0.88672600, '0101000020E6100000A56950340F60ECBFDE921CB0ABD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28187959429.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28187959429.webp', 'https://www.flickr.com/photos/zaragozaantigua/28187959429/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24394, 'Ramв”ңв”Ӯn y Cajal 2005', 'Imagen capturada durante la definitiva fase de rehabilitaciв”ңв”Ӯn del antiguo Convento de Nuestra Seв”ңв–’ora de la Victoria de los PP. Mв”ңВЎnimos de San Francisco de Paula como municipal Museo del Fuego y de los Bomberos. Esta obra fue comenzada en 1998 y quedв”ңв”Ӯ parada poco despuв”ңВ®s. En 2002 fue retomada y en 2003 quedв”ңв”Ӯ de nuevo paralizada. Se retomaron los trabajos en octubre de 2004, con algunas modificaciones respecto al proyecto original, que fueron terminados a finales de 2007, con la idea de inaugurar el museo durante los fastos de la gran Exposiciв”ңв”Ӯn del aв”ңв–’o siguiente. Fue abierto al pв”ңв•‘blico de forma efectiva en junio de 2012. A la izquierda de la imagen, los modernos bloques de viviendas correspondientes al nв”¬в•‘ 36 de la calle de Ramв”ңв”Ӯn y Cajal. Fuente visual: www.zaragoza.es/', 2005, 2005, 2005, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65343700, -0.88631800, '0101000020E61000006765FB90B75CECBF887FD8D2A3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26080451368.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26080451368.webp', 'https://www.flickr.com/photos/zaragozaantigua/26080451368/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24404, 'Convento de los Mв”ңВЎnimos 1875', 'En 1875, el arquitecto municipal Segundo Dв”ңВЎaz realizв”ңв”Ӯ el plano y perfiles del antiguo convento de los frailes Mв”ңВЎnimos de la Victoria, sito entre las calles de Pignatelli y del Hospital, al objeto de realizar modificaciones para su uso como Escuelas (luego Grupo Escolar Ramв”ңв”Ӯn y Cajal, con escuela de niв”ңв–’os, de niв”ңв–’as, y de pв”ңГӯrvulos) y Depв”ңв”Ӯsito municipal. El dibujo representa, asв”ңВЎ, el perfil con el estado del edificio en esa fecha: en el centro, el gran patio central que vertebraba las estancias del antiguo convento, y a la derecha, la gran iglesia y su destacada torre, de principios del siglo XVII. A la iglesia se accedв”ңВЎa por un ensanchamiento de la calle del Hospital al que dio nombre este convento: plaza de la Victoria. Fue desamortizado en 1835 y convertido en cuartel, y mв”ңГӯs tarde en escuela municipal. Durante unas reformas en 1885 la torre y la iglesia fueron derribados. Este espacio es actualmente el municipal Museo del Fuego y de los Bomberos. Fuente visual: www.asociacionlossitios.com/', 1875, 1875, 1875, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65367700, -0.88672600, '0101000020E6100000A56950340F60ECBFDE921CB0ABD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29985184785.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29985184785.webp', 'https://www.flickr.com/photos/zaragozaantigua/29985184785/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24938, 'Monumento a la Madre 1969', 'En 1967, y por suscripciв”ңв”Ӯn popular, se erigiв”ңв”Ӯ en el parque Primo de Rivera el "Monumento a la Madre", de в”ңГјngel Orensanz, situada en la hondonada cercana a las antiguas piscinas infantiles del acceso al Rincв”ңв”Ӯn de Goya (a la izquierda). Este grupo escultв”ңв”Ӯrico ha ido sufriendo primero pintadas, y despuв”ңВ®s la decapitaciв”ңв”Ӯn de los dos bultos redondos. Fuente visual: postal Zerkowitz serie "Zaragoza", en www.delcampe.fr/', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.63202700, -0.89784200, '0101000020E61000001A355F251FBBECBF3198BF42E6D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15675342947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15675342947.webp', 'https://www.flickr.com/photos/zaragozaantigua/15675342947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24428, 'Convento de la Victoria c.1992', 'Imagen capturada en el interior del antiguo patio del convento de La Victoria, reconvertido en sede de los servicios mecв”ңГӯnicos y talleres municipales e inmediato al parque de bomberos de la calle de Ramв”ңв”Ӯn y Cajal. A finales de la dв”ңВ®cada estos servicios fueron reubicados en otras nuevas instalaciones, y el inmueble fue objeto de una intensa y prolongada rehabilitaciв”ңв”Ӯn que en 2012 serв”ңВЎa inaugurado como Museo del Fuego. En la imagen, vista del lado norte del antiguo patio, con acceso desde la calle de Ramв”ңв”Ӯn Pignatelli.', 1992, 1992, 1992, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65392400, -0.88680200, '0101000020E610000065E08096AE60ECBFE60819C8B3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50218471786.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50218471786.webp', 'https://www.flickr.com/photos/zaragozaantigua/50218471786/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24547, 'Calle de la Misericordia 1910', 'Dibujo que representa el proyecto del arquitecto Fв”ңВ®lix Navarro Pв”ңВ®rez para reformar el Garaje de Automв”ңв”Ӯviles Lacarte sito en el nв”ңв•‘mero 2 de la calle de la Misericordia. actual de la Madre Rafols. Domina en в”ңВ®l la estв”ңВ®tica modernista que un par de aв”ңв–’os antes habв”ңВЎa dominado la Exposiciв”ңв”Ӯn Hispano-Francesa.', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65251400, -0.88676200, '0101000020E6100000D8BCAAB35A60ECBF5017299485D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54400948618.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54400948618.webp', 'https://www.flickr.com/photos/zaragozaantigua/54400948618/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25698, 'Pre-Madre Rafols 1899', 'Mateo Lacarte llevaba metido en el negocio de la construcciв”ңв”Ӯn de carruajes desde los aв”ңв–’os 80 del siglo XIX. Su primer taller estuvo en la calle del 5 de marzo. En 1897 comenzв”ңв”Ӯ las gestiones para construir unas nuevas cocheras y talleres de carruajes y de automв”ңв”Ӯviles en la calle de Misericordia nв”¬в•‘ 2, en un solar entre el Cuartel de Pontoneros de Sangenis, y la calle del Hospital . El arquitecto Julio Bravo fue el encargado del proyecto. Tras el в”ңВ®xito de crв”ңВЎtica y pв”ңв•‘blico cosechado por la empresa en la Expo de 1908, estos talleres fueron ampliados con proyecto de Fв”ңВ®lix Navarro, y en 1928 fueron reformados. En la imagen, publicada en la revista "Aragв”ңв”Ӯn Ilustrado", vista de los nuevos talleres y cocheras de la calle de Misericordia. Justo detrв”ңГӯs, uno de los pabellones del cuartel de Sangenis. A la derecha, fuera de plano, la calle del Hospital. Aв”ңв–’os despuв”ңВ®s, estas calles serв”ңВЎan redenominadas, respectivamente, "Madre Rafols" y "Ramв”ңв”Ӯn y Cajal". Fuente: "Zaragoza y la industrializaciв”ңв”Ӯn: la arquitectura industrial en la capital aragonesa entre 1875 y 1936", de Mв”¬В¬ P. Biel Ibв”ңГӯв”ңв–’ez, IFC, 2004.', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65257700, -0.88700600, '0101000020E610000084622B685A62ECBF978FA4A487D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17357775275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17357775275.webp', 'https://www.flickr.com/photos/zaragozaantigua/17357775275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25710, 'Hospital Provincial c.1920', 'Vista de la iglesia del Hospital Provincial, desde la calle de Ramв”ңв”Ӯn y Cajal. Fuente: Foto Jesв”ңв•‘s Cormв”ңГӯn. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65188600, -0.88657800, '0101000020E61000007F4C6BD3D85EECBF315C1D0071D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24914680385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24914680385.webp', 'https://www.flickr.com/photos/zaragozaantigua/24914680385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25718, 'Calle de la Misericordia 1896', 'Imagen capturada en el cuartel de Sangenв”ңВЎs y centrada en el regimiento de Pontoneros allв”ңВЎ establecido y formado en el gran patio de armas. Al fondo y a la izquierda destaca la gran cв”ңв•‘pula del antiguo convento e iglesia de San Ildefonso, consagrado desde 1885 al Sagrado Corazв”ңв”Ӯn de Jesв”ңв•‘s. A la derecha y tras la calle de la Misericordia, pabellв”ңв”Ӯn del Hospital provincial.', 1896, 1896, 1896, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65310600, -0.88825100, '0101000020E61000001D75745C8D6CECBF236937FA98D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54215911806.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54215911806.webp', 'https://www.flickr.com/photos/zaragozaantigua/54215911806/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25818, 'Calle Miguel de Ara 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Ara, (Miguel)." Esta es una larga y estrecha calle que une la calle de San Pablo con la de Pignatelli. En la imagen, tramo de la calle Miguel de Ara desde la calle Agustina de Aragв”ңв”Ӯn, hasta la de Pignatelli. Al fondo, el Parque de Bomberos ubicado en la esquina entre Pignatelli y Ramв”ңв”Ӯn y Cajal.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65429200, -0.88640500, '0101000020E61000002159C0046E5DECBF68041BD7BFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14886567489.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14886567489.webp', 'https://www.flickr.com/photos/zaragozaantigua/14886567489/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25844, 'Calle Miguel de Ara 2006', 'Foto: Esther Casas. Vista de la calle de Miguel de Ara, esquina con la de Agustina de Aragв”ңв”Ӯn. Al fondo, el Parque de Bomberos nв”ңв•‘mero 2, en la calle de Ramв”ңв”Ӯn Pignatelli. Tras la fotв”ңв”Ӯgrafa, la calle del Conde de Aranda. Los andamios del edificio de la derecha anuncian su derribo inminente y la apariciв”ңв”Ӯn de un nuevo solar en esta zona degradada de la ciudad. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65433700, -0.88640700, '0101000020E61000004E417E36725DECBF08C89750C1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32006683731.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32006683731.webp', 'https://www.flickr.com/photos/zaragozaantigua/32006683731/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25847, 'Ramв”ңв”Ӯn y Cajal 1992', 'Imagen centrada en la entrada a la antigua fв”ңГӯbrica de camas de Froilв”ңГӯn Solans en el nв”¬в•‘ 34 de la calle de Ramв”ңв”Ӯn y Cajal, luego redenominada Frutos Solans SA. A la derecha, e inmediato, el que fuera Convento de Nuestra Seв”ңв–’ora de la Victoria de los PP. Mв”ңВЎnimos de San Francisco de Paula, desde 1907 convertido en Parque de Bomberos de la ciudad. Fuente visual: AMZ.', 1992, 1992, 1992, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65343700, -0.88631800, '0101000020E61000006765FB90B75CECBF887FD8D2A3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39919096632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39919096632.webp', 'https://www.flickr.com/photos/zaragozaantigua/39919096632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25851, 'Calle de Pignatelli c.1995', 'Imagen capturada en el tramo de los impares de la calle de Ramв”ңв”Ӯn Pignatelli comprendido entre el despartidero con la calle de Josв”ңВ® Zamoray, y la calle de la Escopeterв”ңВЎa. Casi centra la imagen el Bar-Restaurante-Mesв”ңв”Ӯn El Pajarcico, sito en el nв”¬в•‘ 61 de esta calle. Abierto en 1973 por Eduardo Burgar Asensio, era uno de los lugares de referencia en las inmediaciones al Coso de la Misericordia de la autв”ңВ®ntica "comida casera" autв”ңв”Ӯctona (con perlas culinarias tales que huevos fritos con longaniza, judв”ңВЎas con jarrete, sopa de cocido, morcilla de sangre y arroz), ademв”ңГӯs de contar con una galerв”ңВЎa de decenas de estupendos jamones. Autor desde 1982 de varios libros, como seв”ңв–’ala el anuncio junto a la entrada, "Cada 4 menв”ңв•‘s regalo un libro de mi colecciв”ңв”Ӯn". Este antropolв”ңв”Ӯgico establecimiento de restauraciв”ңв”Ӯn fue cerrado a comienzos de 2013.', 1995, 1995, 1995, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65402800, -0.88789700, '0101000020E6100000ABED26F8A669ECBF8A558330B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48085149282.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48085149282.webp', 'https://www.flickr.com/photos/zaragozaantigua/48085149282/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20908, 'Plano del Arrabal 1776', 'Plano del proyecto de ordenaciв”ңв”Ӯn de las calles del Arrabal de Zaragoza en 1776, con indicaciв”ңв”Ӯn de los hitos del entorno, por Thomas Sanz. Arriba a la izquierda, el Puente de Piedra, seguido del nuevo trazado de su uniв”ңв”Ӯn con la actual avenida de Cataluв”ңв–’a. Aparecen tambiв”ңВ®n los conventos de Altabв”ңГӯs, de San Lв”ңГӯzaro y de Jesв”ңв•‘s, ademв”ңГӯs del Puente de Tablas. Fuente: eszaragoza.blogspot.com.es/2014/09/rabal-de-zaragoza-plan...', 1776, 1776, 1776, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65800000, -0.87185000, '0101000020E61000002E90A0F831E6EBBF4E62105839D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15296644736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15296644736.webp', 'https://www.flickr.com/photos/zaragozaantigua/15296644736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20952, 'Convento de Jesв”ңв•‘s 1855', 'Convento de Jesв”ңв•‘s de Zaragoza. Valentв”ңВЎn Carderera. Lв”ңГӯpiz negro y aguadas sobre papel blanco, 1855. El convento de Nuestra Seв”ңв–’ora de Jesв”ңв•‘s de Zaragoza, fundado en 1447 por los franciscanos, estuvo situado en el Arrabal, dentro del barrio actual del mismo nombre. En 1836 se desacralizв”ңв”Ӯ. En el momento del dibujo, la torre ya habв”ңВЎa perdido el chapitel. Fuente: "Viaje artв”ңВЎstico por Aragв”ңв”Ӯn de Valentв”ңВЎn Carderera", Josв”ңВ® Marв”ңВЎa Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaciв”ңв”Ӯn Lв”ңГӯzaro Galdiano, 2013.', 1855, 1855, 1855, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65732100, -0.87073400, '0101000020E61000000B7DB08C0DDDEBBFADFC321823D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15104343602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15104343602.webp', 'https://www.flickr.com/photos/zaragozaantigua/15104343602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20990, 'Zaragoza 1808', 'En el dibujo, abajo, a la izquierda, figura "Vista de Zaragoza en 1808", aunque el tв”ңВЎtulo oficial de este esbozo es "El puente de piedra sobre el Ebro en Zaragoza". Fue obra de Juan Gв”ңГӯlvez como preparatorio para la serie "Las ruinas de Zaragoza", sobre los desastres de la guerra de 1808-1809. A la izquierda, la fachada de la ciudad en la margen derecha del rв”ңВЎo Ebro, desde la Portaza, hasta el Pilar. El puente de Piedra centra la imagen. A la derecha, el Arrabal, con el convento de San Lв”ңГӯzaro, y unos aguadores, en primer plano, cargando mercancв”ңВЎa del Ebro. Fuente visual: ceres.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65661600, -0.87329600, '0101000020E6100000A148F7730AF2EBBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24868250432.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24868250432.webp', 'https://www.flickr.com/photos/zaragozaantigua/24868250432/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21005, 'El Pilar c.1860', 'Colecciв”ңв”Ӯn Madrazo, Madrid; familia Daza Campos, Madrid (Adquirido en 2006 por el Museo del Prado). Autor anв”ңв”Ӯnimo. Antes de 1880. "Vista posterior de la Basв”ңВЎlica del Pilar de Zaragoza." Imagen capturada desde la ribera izquierda, a la altura del cauce del rв”ңВЎo, incluyendo al Puente de Piedra en el cuadro.', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65729800, -0.87327300, '0101000020E6100000965AEF37DAF1EBBFF4DC425722D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14725216488.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14725216488.webp', 'https://www.flickr.com/photos/zaragozaantigua/14725216488/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21248, 'Convento de San Lв”ңГӯzaro 1907', 'Postal. "Colecciв”ңв”Ӯn Patria y Fe nв”ңв•‘m. 34, Zaragoza 1908 - Centenario de los Sitios", 1907. "Magnв”ңВЎfico edificio emplazado al otro lado del Ebro. El rв”ңВЎo baв”ңв–’a sus cimientos. Fue construido en 1224 por Don Jaime el Conquistador. Su proximidad al puente de Piedra, le hacв”ңВЎa ser apetecido por los franceses, a fin de cortar la comunicaciв”ңв”Ӯn entre Zaragoza y el Arrabal. Palafox lo utilizв”ңв”Ӯ para instalar su cuartel, que fue ocupado el 8 de febrero por los franceses. El 18 del mismo mes, el general, enfermo, fue conducido desde allв”ңВЎ a una casa de la calle de Predicadores." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65791100, -0.87418400, '0101000020E610000083F755B950F9EBBFDE567A6D36D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20151214303.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20151214303.webp', 'https://www.flickr.com/photos/zaragozaantigua/20151214303/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21283, 'Puente de Piedra c.1900', 'Imagen para postal de la Fototipia Hauser y Menet, de Madrid, que captura una vista estв”ңГӯndar de Zaragoza titulada "El puente de Piedra y el Pilar". Fuente visual: www.delcampe.es/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65661600, -0.87329600, '0101000020E6100000A148F7730AF2EBBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24815087470.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24815087470.webp', 'https://www.flickr.com/photos/zaragozaantigua/24815087470/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21378, 'Cuartel de San Lв”ңГӯzaro c.1910', 'En la imagen, detalle de una fotografв”ңВЎa del Archivo Coyne centrada en el Cuartel de San Lв”ңГӯzaro (cuerpo de guardia, o edificio longitudinal flanqueado por dos torreones, patio, y estructura defensiva triangular). A la derecha, refectorio superviviente, aunque muy deteriorado, del antiguo Convento del mismo nombre. Al fondo, la Estaciв”ңв”Ӯn del Norte. Fuente: Pilar Lop Otв”ңВЎn, "Los conventos mercedarios de San Lв”ңГӯzaro y San Pedro Nolasco de Zaragoza", IFC, 2011', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65791100, -0.87418400, '0101000020E610000083F755B950F9EBBFDE567A6D36D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15743356637.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15743356637.webp', 'https://www.flickr.com/photos/zaragozaantigua/15743356637/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21381, 'Vacas en el Ebro c.1910', 'Foto colecciв”ңв”Ӯn Francisco Palв”ңГӯ, entre 1907 y 1912. Vacas abrevando en el rв”ңВЎo Ebro, con el Puente de Piedra y el Pilar al fondo. Fuente: www.facebook.com/photo.php?fbid=813589111997049&set=g...', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65739200, -0.87322100, '0101000020E6100000F8C5A52A6DF1EBBF7653CA6B25D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15861592015.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15861592015.webp', 'https://www.flickr.com/photos/zaragozaantigua/15861592015/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21422, 'Estaciв”ңв”Ӯn del Norte c.1918', 'Imagen del mar de vв”ңВЎas de la estaciв”ңв”Ӯn del Norte junto a los antiguos almacenes y el sifв”ңв”Ӯn que salvaba el cauce de la acequia del Rabal, cerca de la curva que conducв”ңВЎa al talud de la plaza de Altabв”ңГӯs y al tв”ңв•‘nel de San Lв”ңГӯzaro. La fotografв”ңВЎa se habrв”ңВЎa capturado junto a los muelles y andв”ңВ®n principal de la estaciв”ңв”Ӯn. Al fondo, в”ңГӯrboles de la carretera de Cataluв”ңв–’a y cuartel de San Lв”ңГӯzaro, y a la derecha, emerge la atalaya de la Seo, al otro lado del Ebro. A la izquierda, una composiciв”ңв”Ӯn de dos veteranas locomotoras a vapor, posiblemente de la serie 100 (caldera vieja), fabricadas en 1860-61, y desguazadas unos aв”ңв–’os despuв”ңВ®s. Fuente visual: Josep Maria Reitg Martв”ңВЎ, Ajuntament de Girona.', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65861500, -0.87316500, '0101000020E6100000FE60E0B9F7F0EBBFD8D30E7F4DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31695262631.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31695262631.webp', 'https://www.flickr.com/photos/zaragozaantigua/31695262631/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21593, 'Rв”ңВЎo Ebro c.1920', 'Vista de la margen izquierda del rв”ңВЎo Ebro, con el puente de Hierro al fondo. Fuente: Foto Jesв”ңв•‘s Cormв”ңГӯn. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65700700, -0.87219100, '0101000020E610000079B29B19FDE8EBBF1D1F2DCE18D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24870280546.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24870280546.webp', 'https://www.flickr.com/photos/zaragozaantigua/24870280546/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21631, 'Regulares 1922', 'Un grupo de soldados Regulares posa ante el puente de Piedra y el Pilar, desde la orilla del rв”ңВЎo Ebro en su margen izquierda, junto al cuartel de San Lв”ңГӯzaro. Fuente visual: www.todocoleccion.net', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65750300, -0.87353100, '0101000020E61000008159A148F7F3EBBFCD02ED0E29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38863954005.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38863954005.webp', 'https://www.flickr.com/photos/zaragozaantigua/38863954005/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21702, 'Lavaderos del Puente del Pilar c.1935', 'Imagen capturada en el gran lavadero al aire del Puente del Pilar y centrada en la pila de lavar ropa con una zona, en primer tв”ңВ®rmino, para el aclarado de la ropa, y una segunda, posterior, para el lavado con jabв”ңв”Ӯn de tajo, que es donde realizan su trabajo ahora las lavanderas usuarias. A la izquierda y tras la alameda, la extensa zona de los tendederos. A la derecha, el lavadero a cubierto. Al fondo y en la margen derecha emergen la torre de santa Marв”ңВЎa Magdalena, y la torre de San Carlos Borromeo y el seminario sacerdotal.', 1935, 1935, 1935, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65752000, -0.87039500, '0101000020E6100000EE42739D46DAEBBFA33B889D29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15678319991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15678319991.webp', 'https://www.flickr.com/photos/zaragozaantigua/15678319991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22228, 'Arrabal c.1951', 'Desde un tren prв”ңв”Ӯximo a llegar a la estaciв”ңв”Ӯn del Norte, una pixelada imagen realizada a la altura de las traseras del convento de Santa Isabel de las Franciscanas de la Orden Tercera, a la derecha, con ingreso desde el nв”¬в•‘ 2 de la calle del Sobrarbe. La vegataciв”ңв”Ӯn impide ver las traseras del Grupo Escolar Cв”ңГӯndido Domingo. Al fondo, el templo del Pilar.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65858900, -0.87345600, '0101000020E6100000D8D64FFF59F3EBBFAF40F4A44CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49773027303.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49773027303.webp', 'https://www.flickr.com/photos/zaragozaantigua/49773027303/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22508, 'Av. del Puente del Pilar 1962', 'Imagen capturada durante la construcciв”ңв”Ӯn de los grandes bloques de viviendas de renta limitada proyectados por J. M. Anasagasti y F. Barandiarв”ңГӯn para la inmobiliaria Darsa en la manzana delimitada entre la avenida del Puente del Pilar, desde donde se ha tomado la foto, el camino del Puente de Tablas, a la izquierda, y la calle de Jesв”ңв•‘s, al fondo. Esta promociв”ңв”Ӯn se realizв”ңв”Ӯ donde estuvieron los lavaderos del Puente del Pilar.', 1962, 1962, 1962, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65709000, -0.87078400, '0101000020E61000007C293C6876DDEBBFAA436E861BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50874261132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50874261132.webp', 'https://www.flickr.com/photos/zaragozaantigua/50874261132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22554, 'Barrio de Jesв”ңв•‘s c.1978', 'Vista aв”ңВ®rea del barrio de Jesв”ңв•‘s, en su parte mв”ңГӯs inmediata al puente de Hierro y la ribera del Ebro. En primer tв”ңВ®rmino, la antigua fв”ңГӯbrica de colchones Pikolin, que ya en 1973 se habв”ңВЎa trasladado a su nueva factorв”ңВЎa de la carretera de Logroв”ңв–’o. Al otro lado de la avenida del Puente del Pilar, los bloques de viviendas en la esquina con la calle de Cecilio Navarro, levantados en 1960 para empleados de la Compaв”ңв–’в”ңВЎa Telefв”ңв”Ӯnica Nacional de Espaв”ңв–’a. Al fondo y a la izquierda, una de las dos chimeneas de la Azucarera del Arrabal, en un entorno fabril y ferroviario que se extiende hasta el polв”ңВЎgono industrial de Cogullada. Hacia el fondo y a la derecha se despliega el barrio de la Jota, vertebrado entre la avenida de Cataluв”ңв–’a, la calle del Molino de las Armas y la avenida de la Jota. Todavв”ңВЎa perviven campos de cultivo, que irв”ңГӯn siendo urbanizados en aв”ңв–’os posteriores.', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65680100, -0.86994700, '0101000020E6100000221B48179BD6EBBF747D1F0E12D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15046959485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15046959485.webp', 'https://www.flickr.com/photos/zaragozaantigua/15046959485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22665, 'Puente de Hierro 1970', 'Imagen del entorno del puente de Hierro en la margen izquierda mв”ңГӯs inmediata a la ribera del Ebro. Al fondo, construcciв”ңв”Ӯn de los bloques habitacionales entre las calles Cecilio Navarro, Puente de Tablas, calle de Jesв”ңв•‘s, y avenida del puente del Pilar. Fuente visual: Archivo Pв”ңв•‘blico Municipal.', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65667500, -0.86964600, '0101000020E6100000651C23D923D4EBBFE78C28ED0DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22818134690.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22818134690.webp', 'https://www.flickr.com/photos/zaragozaantigua/22818134690/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22686, 'Estaciв”ңв”Ӯn del Norte 1970', 'Imagen en colores del mar de vв”ңВЎas que desde la Estaciв”ңв”Ӯn del Norte, o Arrabal, conducв”ңВЎa por la ribera, pasando el tв”ңв•‘nel de San Lв”ңГӯzaro, hacia Ranillas, el antiguo puente del ferrocarril, y hasta la estaciв”ңв”Ӯn de Delicias, al otro lado del rв”ңВЎo Ebro. A la izquierda, asoma el cuartel de San Lв”ңГӯzaro, en el arranque de la avenida de Cataluв”ңв–’a. A la derecha, parte de las traseras del convento franciscano de Santa Isabel. Por encima sobresale el gigante desarrollista de 10 alturas ubicado entre las calles de Sixto Celorrio y Sobrarbe. Al fondo, la pareja de torres mв”ңГӯs oriental de la iglesia metropolitana de El Pilar. Unos pocos aв”ңв–’os despuв”ңВ®s, este enlace ferroviario, y la propia Estaciв”ңв”Ӯn del Norte, en claro decaimiento tras la apertura del nuevo enlace por Miraflores, serв”ңГӯn cerradas, primero al trв”ңГӯfico de pasajeros, y luego tambiв”ңВ®n al de mercancв”ңВЎas. El desmantelamiento del tendido fue rв”ңГӯpido, al ritmo de los vertiginosos setenta del siglo pasado. Fuente visual: Arxiu Jordi Bibiв”ңГЎ www.flickr.com/photos/jbibia/10120046814/in/album-7215762...', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65861500, -0.87316500, '0101000020E6100000FE60E0B9F7F0EBBFD8D30E7F4DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26750481264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26750481264.webp', 'https://www.flickr.com/photos/zaragozaantigua/26750481264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23000, 'El Ebro aв”ңв–’os 90', 'Vista del rв”ңВЎo Ebro y su margen derecha, desde el puente de Hierro o del Pilar. Al fondo, torres de la Seo y del Pilar. Fuente: Foto para postal de Comercial Josan. Cesiв”ңв”Ӯn de la familia de Josв”ңВ® Marв”ңВЎa Sanz Gonzв”ңГӯlez a Rafael Castillejo. Dataciв”ңв”Ӯn y procesado:', 1990, 1990, 1999, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65665500, -0.87060400, '0101000020E61000007F8978EBFCDBEBBFA0E062450DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26811061864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26811061864.webp', 'https://www.flickr.com/photos/zaragozaantigua/26811061864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23141, 'Aparcamiento de autobuses 2004', 'Foto: Marв”ңВЎa Torres-Solanot. Aspecto del aparcamiento de autobuses sito entre el puente de Piedra (derecha, fuera de plano) y las traseras de la calle de Juliana Larena, en el solar del cuartel de San Lв”ңГӯzaro del barrio Jesв”ңв•‘s. Al fondo a la derecha, edificios de la esquina del Coso con el paseo de Echegaray y Caballero. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2004, 2004, 2004, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65805700, -0.87388700, '0101000020E610000021C9ACDEE1F6EBBFB2F336363BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31836528253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31836528253.webp', 'https://www.flickr.com/photos/zaragozaantigua/31836528253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23177, 'Calle de Funes 2008', 'Imagen de la arrabalera calle de Nicolв”ңГӯs Funes capturada cuando aв”ңв•‘n perduraban, a la derecha, las parcelas de los antiguos nв”ңв•‘meros 6, 8, 10 y 12 de este vial, por cuyas traseras fluв”ңВЎa al aire, en tiempos, la homв”ңв”Ӯnima acequia. Hacia la izquierda se abre la travesв”ңВЎa de Funes, y al fondo la calle se curvea para conducir al antiguo camino de las Tablas. Mв”ңГӯs al fondo, el molino de San Lв”ңГӯzaro y la arbolada ribera del Ebro. Fuente visual: maps.google.es/', 2008, 2008, 2008, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65777300, -0.87155500, '0101000020E6100000F949B54FC7E3EBBF8D98D9E731D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36380144776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36380144776.webp', 'https://www.flickr.com/photos/zaragozaantigua/36380144776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23251, 'Lavadero del Puente del Pilar c.1935', 'Imagen capturada en el gran lavadero al aire del Puente del Pilar y realizada, precisamente, con el fondo de la estructura del puente de Nuestra Seв”ңв–’ora del Pilar que le daba nombre. En primer tв”ңВ®rmino, la pila de lavar ropa con una primera zona para el aclarado de la ropa, y una segunda para el lavado con jabв”ңв”Ӯn de tajo, que es donde posan las lavanderas usuarias. A la izquierda y tras la alameda, la extensa zona de los tendederos.', 1935, 1935, 1935, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65766700, -0.87034300, '0101000020E61000004FAE2990D9D9EBBF4754A86E2ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15494930918.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15494930918.webp', 'https://www.flickr.com/photos/zaragozaantigua/15494930918/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23640, 'Calle de Jesв”ңв•‘s 1969', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 31/05/1969. En la imagen, el antiguo Cuartel de la Guardia Civil de la calle de Jesв”ңв•‘s, nв”¬в•‘ 8, en el tramo hasta la calle Nicolв”ңГӯs Funes.', 1969, 1969, 1969, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65813200, -0.87216800, '0101000020E61000006EC493DDCCE8EBBFBD395CAB3DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15347091381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15347091381.webp', 'https://www.flickr.com/photos/zaragozaantigua/15347091381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23868, 'Zaragoza 1615', 'Escenario para el capв”ңВЎtulo 35 de la serie de dibujos animados "Don Quijote de la Mancha". titulado "Camino de Barcelona". Tв”ңВ®mpera, в”ңГјngel Santiago Chicharro, 1979. Buen aficionado a ver visiones, Alonso Quijano puede observar el futurista templo barroco del Pilar en el emplazamiento en que estaba la iglesia gв”ңв”Ӯtico-mudв”ңВ®jar de Santa Marв”ңВЎa del Pilar. En cualquier caso, en la segunda parte del "Quijote" canв”ңв”Ӯnico, el singular hidalgo de La Mancha pasв”ңв”Ӯ de largo de Zaragoza y se fue a Barcelona. Fuente: www.todocoleccion.net', 1615, 1615, 1615, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65716400, -0.87101400, '0101000020E6100000EA758BC058DFEBBFE50D30F31DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30663941224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30663941224.webp', 'https://www.flickr.com/photos/zaragozaantigua/30663941224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24062, 'Cuartel de San Lв”ңГӯzaro 1975', 'Imagen capturada en el interior del patio del cuartel de San Lв”ңГӯzaro, una lluviosa maв”ңв–’ana de mediados del mes de noviembre, mientras el bombo de la suerte decide el destino castrense donde los jв”ңв”Ӯvenes de la imagen habrв”ңВЎan de realizar el Servicio Militar Obligatorio. La gran mayorв”ңВЎa de ellos tendrв”ңВЎan que hacer turismo a otras regiones, incluyendo la provincia del Sв”ңГӯhara Occidental, entonces inmersa en un complicado proceso de descolonizaciв”ңв”Ӯn, aв”ңв•‘n sin terminar hoy. El pabellв”ңв”Ӯn por donde trepa una enredadera, recayente al arranque de la avenida de Cataluв”ңв–’a, donde estaba el ingreso principal al cuartel. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65821400, -0.87368000, '0101000020E6100000BE6A65C22FF5EBBF7AE2395B40D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32724240024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32724240024.webp', 'https://www.flickr.com/photos/zaragozaantigua/32724240024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24740, 'Convento de San Lв”ңГӯzaro 1890', 'Restos del convento de San Lв”ңГӯzaro de Zaragoza, luego cuartel, en 1890. Este edificio serв”ңГӯ rehabilitado en 1916. Fuente visual: Zaragoza artв”ңВЎstica, monumental e histв”ңв”Ӯrica. Anselmo Gascв”ңв”Ӯn de Gotor, 1891.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65791100, -0.87418400, '0101000020E610000083F755B950F9EBBFDE567A6D36D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15454917010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15454917010.webp', 'https://www.flickr.com/photos/zaragozaantigua/15454917010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24742, 'Circo Tom 1931', 'Observamos cв”ңв”Ӯmo la troupe de un circo con sus carromatos entra a Zaragoza por el puente del Pilar o de Hierro, con la torre de la Seo al fondo. Se dirigen al nuevo recinto ferial de Gran Vв”ңВЎa, una vez inhabilitada la huerta de Santa Engracia para tales fines debido a las nuevas edificaciones. Fuente visual: "De las Fiestas del Pilar: la Feria", ilustraciв”ңв”Ӯn de Vigaray, 11-10-1931, archivo Heraldo de Aragв”ңв”Ӯn, en "Padre Ebro. El rв”ңВЎo Ebro y el siglo XX".', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65679900, -0.87004600, '0101000020E6100000ED7F80B56AD7EBBFD38558FD11D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15561199598.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15561199598.webp', 'https://www.flickr.com/photos/zaragozaantigua/15561199598/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24743, 'Camino de las Tablas 1930', 'Miguel Faci Abad. 1930. Imagen de un arrabalero grupillo de niв”ңв–’os de etnia gitana, en el Barrio de Jesв”ңв•‘s. Al fondo, la margen derecha del Ebro y una vista parcial, tras la fachada del Palacio Arzobispal, del barrio de La Seo. Esta captura se ha realizado cerca del antiguo Puente de Tablas, del que quedaba una referencia en el lugar en que se encontraba esta chiquillerв”ңВЎa: cerca del Camino de las Tablas, actual Calle Puente Tablas. A derecha e izquierda de esta imagen, tendederos y lavaderos como el de Modesto Andrв”ңВ®s. Fuente visual: "Miguel y Gabriel Faci. Fotв”ңв”Ӯgrafos fundadores de la Real Sociedad Fotogrв”ңГӯfica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciв”ңв”Ӯn Provincial de Zaragoza, 1999.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.65723400, -0.87109500, '0101000020E61000001CB1169F02E0EBBFDEE8633E20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15574237569.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15574237569.webp', 'https://www.flickr.com/photos/zaragozaantigua/15574237569/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24747, 'Cuartel de San Lв”ңГӯzaro c.1888', 'Imagen del patio del cuartel de San Lв”ңГӯzaro, hacia 1888. Al fondo, el Pilar. Fuente: www.facebook.com/photo.php?fbid=10204391339677174&set...', 1888, 1888, 1888, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65791100, -0.87418400, '0101000020E610000083F755B950F9EBBFDE567A6D36D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15747087251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15747087251.webp', 'https://www.flickr.com/photos/zaragozaantigua/15747087251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24769, 'Avenida Puente del Pilar 1990', 'Foto: Mariano Aladrв”ңВ®n. Vista de la avenida Puente del Pilar desde el paso homв”ңв”Ӯnimo sobre el Ebro, en 1990. Fuente: www.facebook.com/photo.php?fbid=10153056294537834&set...', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65677600, -0.87005500, '0101000020E6100000BA1457957DD7EBBF1B66683C11D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21649235600.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21649235600.webp', 'https://www.flickr.com/photos/zaragozaantigua/21649235600/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24771, 'Avenida Puente del Pilar 1990', 'Foto: Mariano Aladrв”ңВ®n. Vista de la avenida Puente del Pilar con el puente homв”ңв”Ӯnimo sobre el Ebro al fondo, en 1990. Fuente: www.facebook.com/photo.php?fbid=10153055973112834&set...', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65721700, -0.86972300, '0101000020E61000003C873254C5D4EBBF08B0C8AF1FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22283360229.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22283360229.webp', 'https://www.flickr.com/photos/zaragozaantigua/22283360229/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24794, 'San Lв”ңГӯzaro 2009', 'Obras de construcciв”ңв”Ӯn del Centro de Interpretaciв”ңв”Ӯn de San Lв”ңГӯzaro, en octubre de 2009. Alberga restos del convento (1224), luego cuartel, derribado en 1983. Este pequeв”ңв–’o museo permaneciв”ңв”Ӯ cerrado durante aв”ңв–’os, hasta que en 2016 se recuperaron las visitas, tras breves perв”ңВЎodos en 2010 y 2013. Fuente visual: Heraldo de Aragв”ңв”Ӯn.', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65801700, -0.87414400, '0101000020E6100000F6D37FD6FCF8EBBF249BABE639D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32470418653.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32470418653.webp', 'https://www.flickr.com/photos/zaragozaantigua/32470418653/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22715, 'Romareda 1976', 'Imagen capturada desde la altura de la torre de la Feria de Muestras con una interesante panorв”ңГӯmica del entorno del inmediato polв”ңВЎgono de la Romareda (antiguo de la Gran Vв”ңВЎa). A la izquierda, el paseo de Isabel la Catв”ңв”Ӯlica con la Residencia Sanitaria "Josв”ңВ® Antonio", el Colegio-Residencia de Nuestra Seв”ңв–’ora del Pilar para Huв”ңВ®rfanos e Hijos del Magisterio, y las destacadas torres de viviendas ubicadas al final del paseo. En el centro de la imagen, original estadio municipal de La Romareda durante el comienzo de las obras de ampliaciв”ңв”Ӯn y cubrimiento de las Tribunas de Gol Norte y Gol Sur, realizadas por la empresa constructora Obrascв”ңв”Ӯn SA (integrante luego de la actual OHL) y que culminarв”ңВЎan en agosto del aв”ңв–’o siguiente tras casi duplicar durante el proceso el presupuesto inicial consignado, algo que en la larga etapa interdemocrв”ңГӯtica no se publicitaba, luego no existв”ңВЎa, asociado a conceptos como "sobrecostes", "mordidas", o "corrupciв”ңв”Ӯn" (que incluye tanto a corruptores como corruptos). A la derecha, iglesia parroquial de Santa Mв”ңв”Ӯnica y vista parcial, al fondo, del Seminario. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63655900, -0.90191300, '0101000020E6100000BCCADAA678DCECBFBB7CEBC37AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29919916448.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29919916448.webp', 'https://www.flickr.com/photos/zaragozaantigua/29919916448/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24796, 'Calle de Jesв”ңв•‘s 2008', 'Imagen capturada en la calle de Jesв”ңв•‘s, durante el parв”ңв”Ӯn de la construcciв”ңв”Ӯn por la empresa (entre otras cosas) Sacyr Vallehermoso de las 197 viviendas de lujo de la inmediata parcela, aquв”ңВЎ delimitada apenas por una red verde. Este proyecto, denominado "Balcв”ңв”Ӯn de San Lв”ңГӯzaro", arrancв”ңв”Ӯ en el aв”ңв–’o 2006 con el horizonte de que durante el prodigioso verano de 2008, en plena Expo, empezara a ser ocupado por residentes, y convertirse asв”ңВЎ en otra gran empresa realizada al hilo de la muestra internacional. Pero al poco de comenzar los trabajos de excavaciв”ңв”Ӯn de los cimientos y garajes, aparecieron sorprendentes restos arqueolв”ңв”Ӯgicos posiblemente vinculados al convento mercedario de San Lв”ңГӯzaro allв”ңВЎ fundado en el siglo XIII, asв”ңВЎ como un refugio aв”ңВ®reo habilitado durante la guerra civil de 1936-39 en los bajos del cuartel homв”ңв”Ӯnimo que allв”ңВЎ funcionв”ңв”Ӯ durante casi un siglo. Tras un parв”ңв”Ӯn tв”ңВ®cnico prolongado, las obras retomaron su impulso definitivo en 2014 por la gestora Gestiв”ңв”Ӯn Comв”ңв•‘n, y la constructora Ferrovial. Centra la imagen el sesentero inmueble del nв”¬в•‘ 1 de la calle de Juliana Larena, в”ңв•‘nico testigo que perdura de la traza urbana de este tramo de la calle de Jesв”ңв•‘s. A su izquierda, el gran solar que perdura tras el derribo del cuartel de la Guardia Civil. A su derecha y al fondo, el antiguo molino de la Sal de San Lв”ңГӯzaro, y la ribera del rв”ңВЎo Ebro. En primer tв”ңВ®rmino, y confrontando al otro lado de la calle, solar del desaparecido inmueble del nв”¬в•‘ 2 de la calle de Jesв”ңв•‘s, en cuyos bajos estuvo el Cine Norte. Fuente visual: www.google.com/maps', 2008, 2008, 2008, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65817400, -0.87270300, '0101000020E6100000F4DF83D72EEDEBBFEC89AE0B3FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32790433218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32790433218.webp', 'https://www.flickr.com/photos/zaragozaantigua/32790433218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24816, 'Calle del Sobrarbe c.1893', 'Imagen capturada aprovechando el saliente sol, posiblemente desde la altura de la torre sureв”ңв–’a de la moderna iglesia parroquial de Nuestra Seв”ңв–’ora de Altabв”ңГӯs, construida sobre una parte del antiguo Macelo, con una mв”ңГӯs que interesante vista panorв”ңГӯmica de la ciudad desde la margen izquierda. En primer tв”ңВ®rmino, la calle del Sobrarbe y sus varias alturas o niveles. A la izquierda, e inmediatos, tejados del antiguo Macelo municipal y del convento de las carmelitas de San Josв”ңВ® del Arrabal. A la derecha, manzana delimitada entre la calle del Horno y la calle de Juslibol. Antes del Puente de Piedra destaca la zanja del empalme del ferrocarril a las lв”ңВЎneas de Barcelona y Pamplona, cubierta con el paso a la calle del Sobrarbe, por donde transitaban los tranvв”ңВЎas a propulsiв”ңв”Ӯn de sangre de la linea del Arrabal. Hacia la izquierda hacв”ңВЎan lo propio, por la carretera de Madrid a Barcelona, los de la lв”ңВЎnea del Gв”ңГӯllego. Hacia la derecha, el arranque de la ribereв”ңв–’a arboleda de Macanaz. Pasado el Ebro, panorв”ңГӯmica edilicia con la monumental fachada del Palacio Arzobispal, tras el que emerge la torre y cimborrio de la Seo. Donde se abre la calle de la Lonja se destaca al fondo la torre de la iglesia de San Juan y San Pedro. A la derecha, la veterana Casa Consistorial y la Lonja como su anexo. Difumimada al fondo, la torre de la iglesia de San Gil Abad. A la derecha, tras la casa del marquв”ңВ®s de Ayerbe y la Casa de los Infantes, el templo del Pilar y su reciв”ңВ®n terminada torre de Santiago.', 1893, 1893, 1893, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65886900, -0.87431400, '0101000020E610000010EB8D5A61FAEBBF93ACC3D155D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49008106072.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49008106072.webp', 'https://www.flickr.com/photos/zaragozaantigua/49008106072/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24825, 'Av. del Puente del Pilar c.1992', 'La avenida del Puente del Pilar durante las obras de renovaciв”ңв”Ӯn de conducciones y pavimentos, en una imagen capturada junto a las antiguas naves de Pikolв”ңВЎn, a la derecha, con una vista que alcanza desde el inmediato cruce con la calle del Pilar y el camino del Vado, hasta el fondo donde en la avenida de Cataluв”ңв–’a se perfilan la Casa Aв”ңВЎsa Farasduв”ңВ®s o Casa Solв”ңГӯns y la antigua fв”ңГӯbrica de galletas Patria, e incluso los recientes bloques de la calle del Marquв”ңВ®s de la Cadena y la plaza de W. Amadeus Mozart.', 1992, 1992, 1992, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65749900, -0.86950700, '0101000020E61000000C94145800D3EBBF8C135FED28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50450894223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50450894223.webp', 'https://www.flickr.com/photos/zaragozaantigua/50450894223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25405, 'Desde San Lв”ңГӯzaro c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Cв”ңВЎa. 1860-1886. "Puente sobre el Ebro desde las ruinas de San Lв”ңГӯzaro". Puente de Piedra, con el Pilar al fondo.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65806800, -0.87430300, '0101000020E6100000166EF9484AFAEBBFA6457D923BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14843705646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14843705646.webp', 'https://www.flickr.com/photos/zaragozaantigua/14843705646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25407, 'Ribera del Ebro 1957', 'Un grupo de reclutas durante el servicio militar obligatorio o mili en el cuartel de San Lв”ңГӯzaro, establecido a finales del siglo XIX sobre el antiguo convento del mismo nombre, posan en la ribera del Ebro con el fondo del puente de Piedra y el Pilar, del que destacan sus dos в”ңв•‘ltimas torres en construcciв”ңв”Ӯn. Fuente: Colecciв”ңв”Ӯn Joaquв”ңВЎn Cabezas.', 1957, 1957, 1957, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65776300, -0.87389500, '0101000020E6100000D769A4A5F2F6EBBF6AC2F69331D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14914204126.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14914204126.webp', 'https://www.flickr.com/photos/zaragozaantigua/14914204126/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25445, 'Puente de Tablas 2007', 'Estribo norte del puente de Tablas, excavado durante las obras de remodelaciв”ңв”Ӯn del paseo de la Ribera, entre el puente del Pilar y el de Piedra. El antiguo puente de Tablas sobre el rв”ңВЎo Ebro para paso de la carretera real de Madrid a Barcelona fue reconstruido tras varias riadas, como la de febrero de 1643 o la del 23 de junio de 1775. Una nueva avenida, el 10 de junio de 1801, acabв”ңв”Ӯ para siempre con в”ңВ®l. En 1803 se proyectв”ңв”Ӯ levantarlo de nuevo, pero hasta 1895 no se inaugurв”ңв”Ӯ el puente del Pilar, en sus inmediaciones. En 2008, en esta ubicaciв”ңв”Ӯn se inaugurв”ңв”Ӯ un mirador diseв”ңв–’ado por Claus Bury, dentro del programa de Intervenciones Artв”ңВЎsticas de la Expo. Fuente visual: Heraldo de Aragв”ңв”Ӯn.', 2007, 2007, 2007, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65679000, -0.87131200, '0101000020E6100000639813B4C9E1EBBF802BD9B111D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32306673092.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32306673092.webp', 'https://www.flickr.com/photos/zaragozaantigua/32306673092/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25862, 'Calle de Jesв”ңв•‘s 2007', 'Instantв”ңГӯnea de las traseras del edificio de la calle de Jesв”ңв•‘s 2, en el momento de ser derribado en febrero de 2007. Albergaba en sus bajos el cine Norte, abierto entre 1953 y 1981. Fuente visual: demoliciones.usabiaga.com/', 2007, 2007, 2007, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65821100, -0.87287700, '0101000020E610000069C70DBF9BEEEBBF096F0F4240D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21923079511.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21923079511.webp', 'https://www.flickr.com/photos/zaragozaantigua/21923079511/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25866, 'Calle de Jesв”ңв•‘s 2007', 'Foto: Marв”ңВЎa Torres-Solanot. Derribo del edificio del nв”ңв•‘mero 2 de la calle de Jesв”ңв•‘s, en febrero de 2007. Albergaba en sus bajos el cine Norte, abierto entre 1953 y 1981, con su puerta principal, en la imagen, tras el semв”ңГӯforo. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2007, 2007, 2007, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65828100, -0.87286800, '0101000020E61000009C3237DF88EEEBBF024A438D42D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31861913510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31861913510.webp', 'https://www.flickr.com/photos/zaragozaantigua/31861913510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25989, 'Zaragoza 1749', 'Dibujo de Luis Macaya para la ediciв”ңв”Ӯn argentina de 1943 del Г”ГҮВЈDiario y derrotero de los viajes que ha hecho el Padre Fray Pedro Josв”ңВ® de Parras, desde que saliв”ңв”Ӯ de la ciudad de Zaragoza, en Aragв”ңв”Ӯn, para la Amв”ңВ®rica; con una brevв”ңВЎsima relaciв”ңв”Ӯn de lo que personalmente ha experimentado en diversos paв”ңВЎses y de las cosas mв”ңГӯs notables que en ellos ha vistoГ”ГҮГҳ (1749-1753), escrito por el turolense Pedro Josв”ңВ® de Parras, que viajв”ңв”Ӯ de Cariв”ңв–’ena a Paraguay. La ilustraciв”ңв”Ӯn refleja el estado de la ciudad a principios del siglo XX, aunque se refiere a 1749. El fraile dice de su paso por Zaragoza: "No omitirв”ңВ® ser esta ciudad la mв”ңГӯs hermosa y aseada que he visto en lo que he transitado. Tiene despejadв”ңВЎsimas calles, y la que llaman del Coso, no tiene en Espaв”ңв–’a semejante. Sв”ңв”Ӯlo la calle de Alcalв”ңГӯ, en Madrid, le parece un poco, pero no es tan buena. Tiene asв”ңВЎ mismo cerca de cincuenta comunidades. Sujetas al provincial de San Francisco, hay seis. Son suntuosos sus palacios. En una o en otra ciudad, se hallarв”ңГӯ algв”ңв•‘n templo que iguale a los de Zaragoza, pero a todos juntos no pueden compararse los de alguna otra ciudad, fuera de Roma. La Universidad es famosa y bien formalizada, y los estudios en ninguna parte se hallarв”ңГӯn mв”ңГӯs florecientes que en este reino. La ciudad tiene fertilв”ңВЎsima ribera y varios floridв”ңВЎsimos monasterios en lo mв”ңГӯs ameno de sus huertas, y entre todos sobresalen las dos cartujas de la Concepciв”ңв”Ӯn y Aula Dei. Bв”ңГӯв”ңв–’anle dos rв”ңВЎos muy caudalosos; el uno es Gв”ңГӯllego y el otro Ebro, que es navegable hasta Tortosa, y que no hay otro en Espaв”ңв–’a que pueda igualarle, sв”ңВЎ sв”ңв”Ӯlo Guadalquivir. Sв”ңв”Ӯlo tiene un defecto, y es no sea puerto de mar; por cuya causa estв”ңГӯ la ciudad sin aquel concurso de gente que es capaz, aunque siempre estв”ңГӯ bien surtida de tropa. Abunda mucho de aceite, vino, lanas, frutas, hortalizas, lino, seda, y finalmente, hay con abundancia de cuantos efectos produce la Espaв”ңв–’a. Tiene la ciudad Audiencia, Tribunal de Inquisiciв”ңв”Ӯn, capitв”ңГӯn general del Reino, intendente de la Real Hac', 1749, 1749, 1749, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65753600, -0.87367200, '0101000020E610000008CA6DFB1EF5EBBFA9F8BF232AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18834347511.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18834347511.webp', 'https://www.flickr.com/photos/zaragozaantigua/18834347511/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26017, 'Playas del Ebro 1968', 'Veraniega imagen de una de las famosas playas del Ebro como interesante destino del turismo interior en la Espaв”ңв–’a del "milagro" econв”ңв”Ӯmico, en la prodigiosa dв”ңВ®cada. La captura se ha realizado en las traseras del Colegio de San Miguel, antiguo molino de sal y harina, y una de las playas urbanas durante el estв”ңВЎo. La calidad del agua no era muy alta, el estado de la ribera dejaba bastante que desear, y las escombreras de primer tв”ңВ®rmino deslucв”ңВЎan un poco la cosa, pero los estв”ңГӯndares de calidad de la concurrencia no eran demasiado puntillosos. Eso sв”ңВЎ, la vista de la magnв”ңВЎfica margen derecha, con el puente de Piedra, el Pilar, el Ayuntamiento, la Lonja, el palacio Arzobispal... et cetera, lucв”ңВЎa inmejorable. En Zaragoza, con un neumв”ңГӯtico, y un paraguas, ya tienes baв”ңв–’os de sol y agua, al menos en aquellos aв”ңв–’os. Fuente visual: Walter Schrв”ңГӮder (www.bildindex.de/)', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65669900, -0.87154500, '0101000020E610000016C1FF56B2E3EBBF70287CB60ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23227617450.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23227617450.webp', 'https://www.flickr.com/photos/zaragozaantigua/23227617450/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26049, 'Ribera del Ebro 2006', 'Foto: Marв”ңВЎa Torres-Solanot. Diciembre de 2006. Vista de la explanaciв”ңв”Ӯn de los terrenos, tras el derribo de las naves que allв”ңВЎ habв”ңВЎa, del tramo de ribera del Ebro entre los puentes de Hierro y de Piedra (al fondo). Esta zona trasera del barrio de Jesв”ңв•‘s es conocida como Balcв”ңв”Ӯn de San Lв”ңГӯzaro. El edificio que permanece en pie es el antiguo molino de la sal, luego colegio de San Miguel, abandonado a finales de los setenta. Hoy es un restaurante. El otro edificio que dejarв”ңГӯ en pie esta actuaciв”ңв”Ӯn es el del antiguo cine Norte, en la calle de Jesв”ңв•‘s 2; serв”ңГӯ derribado en febrero de 2007. El entorno, urbanizado mediante un vial y la construcciв”ңв”Ӯn de edificios (a la derecha), recibirв”ңГӯ despuв”ңВ®s el nombre de paseo de la Ribera, como los tramos que lo acompaв”ңв–’an a este y oeste. Al fondo, paseo de Echegaray y Caballero, con las torres de la Seo y el Pilar. Fuente: Heraldo de Aragв”ңв”Ӯn.', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HISTв”ңГҙRICO', 41.65707900, -0.87149400, '0101000020E61000008E20956247E3EBBFB7F1272A1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32002422512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32002422512.webp', 'https://www.flickr.com/photos/zaragozaantigua/32002422512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21260, 'Plaza de las Eras 1907', 'Postal. "Colecciв”ңв”Ӯn Patria y Fe nв”ңв•‘m. 38, Zaragoza 1908 - Centenario de los Sitios", 1907. "Escenario de muy reв”ңв–’idas campaв”ңв–’as por su proximidad a los conventos de San Agustв”ңВЎn y Santa Mв”ңв”Ӯnica que fueron constante blanco de las baterв”ңВЎas francesas y brecha por donde intentaron penetrar uno y otro dв”ңВЎa." En la imagen, la plaza desde la fuente de agua que habв”ңВЎa en su centro. Hacia la izquierda, continв”ңв•‘a la calle Manuela Sancho para desembocar mв”ңГӯs adelante en la calle Doctor Palomar. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65015400, -0.87174000, '0101000020E610000068AED3484BE5EBBF8AAE0B3F38D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20584647970.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20584647970.webp', 'https://www.flickr.com/photos/zaragozaantigua/20584647970/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21953, 'Convento Capuchinas c.1943', 'Fachada del Convento de las Madres Clarisas Capuchinas, calle Manuela Sancho 40. Esta congregaciв”ңв”Ӯn vino a Zaragoza desde Barcelona a comienzos del siglo XVII, y se instalaron justo enfrente del convento de las MM. Carmelitas Descalzas, en la plaza de Santa Engracia. En el siglo XIX, la reordenaciв”ңв”Ӯn urbana del nuevo Salв”ңв”Ӯn de Santa Engracia les dejв”ңв”Ӯ sin sitio, y anduvieron unos aв”ңв–’os en la provisionalidad. En 1877 se instalaron en la calle Manuela Sancho, en un convento de nueva planta diseв”ңв–’ado por Pascual Bravo hasta que, menos de un siglo despuв”ңВ®s, otro ejemplo de la no oficial "Operaciв”ңв”Ӯn Conventos y Colegios Privados", vendieron y se trasladaron a la periferia, calle Monasterio de Nuestra Seв”ңв–’ora de los в”ңГјngeles (mв”ңГӯs allв”ңГӯ de la Vв”ңВЎa Hispanidad). El convento de la imagen fue derribado en 1973, y sobre в”ңВ®l se levantв”ңв”Ӯ la urbanizaciв”ңв”Ӯn hoy existente, entre la calle Manuela Sancho, y la calle Asalto. Fuente visual: Dibujo de Ambrosio Ruste en la revista La Cadiera.', 1943, 1943, 1943, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.64988200, -0.87165400, '0101000020E6100000C5AEEDED96E4EBBF292158552FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19302059572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19302059572.webp', 'https://www.flickr.com/photos/zaragozaantigua/19302059572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23589, 'Torre de Bruil c.1959', 'Imagen de la fachada recayente a la calle del Asalto, confrontando con el convento de religiosas de Santa Mв”ңв”Ӯnica, de la denominada Torre de Bruil (1842-1868), que aunque desde 1878 era propiedad de la familia Monserrat, conservв”ңв”Ӯ su original nombre de forma no oficial. Los de la imagen eran los edificios tras los que se abrв”ңВЎa el ordenado juego de paseos, pв”ңВ®rgolas, arbolado y vegetaciв”ңв”Ӯn decorativa que caracterizaba este decimonв”ңв”Ӯnico y singular espacio de recreo, trufado de enclaves bizarros como su montaв”ңв–’a artificial. A comienzos de los aв”ңв–’os 50 del siglo XX el Ayuntamiento iniciв”ңв”Ӯ el proceso para expropiar este terreno y convertirlo en un parque pв”ңв•‘blico. En 1959 los tribunales ratificaron esta pretensiв”ңв”Ӯn, y a cambio casi cinco millones y medio de pesetas pagadas al propietario, su titularidad pasв”ңв”Ӯ a beneficio de la ciudad. Poco despuв”ңВ®s, tras una intensa remodelaciв”ңв”Ӯn que incluyв”ңв”Ӯ el derribo de estos inmuebles, serв”ңВЎa inaugurado como Parque Bruil.', 1959, 1959, 1959, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.65022800, -0.87001200, '0101000020E6100000E814E46723D7EBBFC478CDAB3AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50068064947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50068064947.webp', 'https://www.flickr.com/photos/zaragozaantigua/50068064947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23592, 'Plaza de las Eras 1990', 'Imagen capturada desde la altura del inmueble del nв”¬в•‘ 40 de la calle de Manuela Sancho, con vista de la plaza de las Eras previa a la reforma que, tras la renovaciв”ңв”Ӯn de servicios, evitarв”ңВЎa que este espacio siguiera siendo bв”ңГӯsicamente un aparcamiento en superficie. Entre los nuevos elementos decorativos de la nueva plaza, destacarв”ңВЎan unas singulares pв”ңВ®rgolas, y una escultura en bronce de la mitolв”ңв”Ӯgica diosa Hera, con homofonв”ңВЎa idв”ңВ®ntica que el nombre de la plaza, aunque su simbolismo no tuviera nada que ver con ella. Tal vez por ello, y por estar dispuesta en altura en un espacio pequeв”ңв–’o, resulta ser una de las esculturas mв”ңГӯs inapreciables de la ciudad.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTв”ңГҙRICO', 41.65015600, -0.87177100, '0101000020E6100000293DD34B8CE5EBBF2BA6D24F38D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50370134818.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50370134818.webp', 'https://www.flickr.com/photos/zaragozaantigua/50370134818/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23714, 'Escuelas del Terminillo 1923', 'Aspecto de la entrada al edificio de las Escuelas del Terminillo o Escuela Asilo de las Hermanas de San Vicente de Paв”ңв•‘l, fundada por el arzobispo Juan Soldevila en 1914. La foto se ha tomado en el lugar donde в”ңВ®ste muriв”ңв”Ӯ a causa de los disparos de un comando anarquista. Un mausoleo fue levantado allв”ңВЎ, que permaneciв”ңв”Ӯ en las traseras del Colegio Santa Marв”ңВЎa Reina, calle La Milagrosa, hasta 2024. Entonces esa cruz-monolito fue trasladada al patio del Cedro del palacio Arzobispal, en la esquina de la calle del Sepulcro con la plaza de San Bruno. Fuente: eszaragoza.blogspot.com', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.64452000, -0.90479400, '0101000020E6100000A9BEF38B12F4ECBF18CFA0A17FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26134114535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26134114535.webp', 'https://www.flickr.com/photos/zaragozaantigua/26134114535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23599, 'Cisterna romana siglo I', 'La mayor cisterna romana hallada en Zaragoza, excavada entre 1990 y 1991, se ubicaba en el actual entorno de la plaza de las Eras, concretamente en el solar que ocupa el actual edificio de la calle de Manuela Sancho 50, construido en 2001. Ese solar, en forma de Г”ГҮВЈLГ”ГҮГҳ, estuvo ocupado antes de su excavaciв”ңв”Ӯn por edificaciones situadas entre la actual calle del Asalto 69 y la de Cantв”ңВЎn y Gamboa 34, junto al convento de las Madres Clarisas Capuchinas (1877-1973) de la calle de Manuela Sancho 40. El periodista Mariano Garcв”ңВЎa publicв”ңв”Ӯ en Heraldo de Aragв”ңв”Ӯn el 10 de enero de 2026 un artв”ңВЎculo en el que divulgaba el estudio de Francisco de Asв”ңВЎs Escudero Escudero y Marв”ңВЎa Pilar Galve Izquierdo sobre "La cisterna romana de la plaza Eras de Zaragoza y otras cisternas y depв”ңв”Ӯsitos de Caesaraugusta", incluido en el libro "Aquae Urbium. El ciclo urbano del agua en la Hispania romana" (Editorial Universidad de Sevilla, 2025). En ese estudio los autores destacan que la cisterna, construida a finales del siglo I o comienzos del II, es la mв”ңГӯs importante hallada en Zaragoza, debido a sus grandes dimensiones. Pese a que su planta rectangular no se hallв”ңв”Ӯ completa, de los restos se infiriв”ңв”Ӯ que tuvo una superficie cercana a los 90 metros cuadrados. Estaba construida con opus caementicium (hormigв”ңв”Ӯn romano), y sus muros tenв”ңВЎan un grosor de al menos dos metros. Eso hace suponer que el edificio era de altura considerable, que lo harв”ңВЎa visible desde gran parte de la ciudad. Un tubo de plomo conservado, por el que desaguaba la cisterna, se hallaba a cierta altura, lo que confirmaba la funciв”ңв”Ӯn de decantaciв”ңв”Ӯn de la estructura, dejando en el fondo del depв”ңв”Ӯsito las impurezas. El agua almacenada provendrв”ңВЎa de un castellum aquae (cisterna principal), situado posiblemente al sur de la ciudad, en el actual eje del paseo de la Independencia. Contrariamente a la tesis defendida hasta ahora, ello confirmarв”ңВЎa que el agua de boca de la ciudad provenв”ңВЎa del rв”ңВЎo Huerva, y no del Gв”ңГӯllego. Tambiв”ңВ®n se han encontrado otr', 50, NULL, 99, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.64993300, -0.87132300, '0101000020E61000005D15A8C5E0E1EBBFABCB290131D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/55037984470.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/55037984470.webp', 'https://www.flickr.com/photos/zaragozaantigua/55037984470/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23981, 'Los Viejos 2. 1975', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 27/02/1975. Callle Los Viejos desde esquina con El Turco. Al fondo, la calle de la Torre. Un cuerpo cubierto bajo una sв”ңГӯbaba, tendido en el suelo. Una dotaciв”ңв”Ӯn de la Policв”ңВЎa Armada espera en el escenario de los hechos, mientras llegan los inspectores. Gente curiosa alparcea.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65014800, -0.87319100, '0101000020E61000004E2B85402EF1EBBFA8C7B60C38D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15330027322.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15330027322.webp', 'https://www.flickr.com/photos/zaragozaantigua/15330027322/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24162, 'Calle del Asalto 1931', 'Imagen capturada en la calle del Asalto durante el desarrollo del tradicional Ferial de Ganados que en ese entorno se celebraba con ocasiв”ңв”Ӯn de las fiestas mayores de la localidad, en octubre. Este ferial tuvo dos ubicaciones: una primera, en el paseo de la Mina, entre los viveros del Ayuntamiento junto al puente de San Josв”ңВ® y la calle de Moret, y la de la imagen, en la calle del Asalto entre el Corral de Abastos de Intendencia y el convento de las Capuchinas. Allв”ңВЎ, la compra y venta de caballerв”ңВЎas menores y mayores suponв”ңВЎa un importante trasiego de personas asв”ңВЎ como el cambio de mano de muchos miles de duros. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTв”ңГҙRICO', 41.64926300, -0.87243500, '0101000020E610000025581CCEFCEAEBBF5DC0CB0C1BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36435520482.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36435520482.webp', 'https://www.flickr.com/photos/zaragozaantigua/36435520482/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24447, 'Fielato calle Asalto 1961', 'Archivo Municipal de Zaragoza. JARKE-JARIA. 22/VII/1961. "Inauguraciв”ңв”Ӯn del fielato de la calle Asalto." "Fielato" era el nombre que recibв”ңВЎan las casetas de cobro de arbitrios y tasas municipales sobre trв”ңГӯfico de mercancв”ңВЎas ("fielato": fiel o balanza para calcular el peaje). Su nombre oficial era "Estaciв”ңв”Ӯn Sanitaria" ya que, ademв”ңГӯs de su funciв”ңв”Ӯn recaudatoria, controlaban el estado sanitario de los alimentos que entraban en la ciudad. En la imagen, "fielato" reciв”ңВ®n inaugurado en la calle Asalto, junto al Depв”ңв”Ӯsito Corral de la Leв”ңв–’a del Ejв”ңВ®rcito (a la derecha), y el nuevo puente sobre el rв”ңВЎo Huerva que conectaba con las traseras del Cuartel de Intendencia de San Josв”ңВ® (a la izquierda). Por encima de los в”ңГӯrboles, una de las chimeneas de la antigua fв”ңГӯbrica de regaliz.', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.64917800, -0.87144900, '0101000020E61000008F386403E9E2EBBF2FA4C34318D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15181901888.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15181901888.webp', 'https://www.flickr.com/photos/zaragozaantigua/15181901888/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24454, 'Pl. de las Heras 1925', 'Los "grandes talleres mecв”ңГӯnicos de serrerв”ңВЎa y carpinterв”ңВЎa Manuel Soria Larios" estaban ubicados sobre un amplio solar de 1.500 m2 entre las calles de Alcalв”ңГӯ, Manuela Sancho, y la plaza de las Eras. Surtв”ңВЎan de madera trabajada a obras de construcciв”ңв”Ӯn, llegando a abastecer a notables proyectos de arquitectos como Julio Bravo Folch (ya fallecido), y Francisco Albiв”ңв–’ana (serв”ңГӯ fusilado en Valdespartera 9 aв”ңв–’os despuв”ңВ®s). En la imagen, aspecto del enorme edificio de dos plantas sede de los talleres. La captura ha sido realizada desde la plaza de las Heras. A la izquierda, se levantaba el inmediato convento de las MM. Capuchinas. Este goloso edificio llegв”ңв”Ӯ intacto hasta finales de la dв”ңВ®cada de los aв”ңв–’os 60 del pasado siglo, cuando fue piqueteado y sustituido por un compacto, macizo y anodino bloque de viviendas de ocho alturas de los del desarrollismo, de esos a los que les da igual estar en la plaza de las Eras, que en la calle del Doce de Octubre. Fuente visual: revista "La Esfera", setiembre 1925.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65001100, -0.87182500, '0101000020E6100000F5B9DA8AFDE5EBBF2785798F33D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17370283471.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17370283471.webp', 'https://www.flickr.com/photos/zaragozaantigua/17370283471/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24960, 'Parque Bruil. Oso Juan 1973', 'Desde su inauguraciв”ңв”Ӯn en 1965 como espacio pв”ңв•‘blico municipal, el Parque Bruil albergaba un pequeв”ңв–’o Г”ГҮВЈzooГ”ГҮГҳ de animales irracionales como monos, pavos reales, y una pareja de osos, Г”ГҮВЈJuanГ”ГҮГҳ, el chico, y Г”ГҮВЈNicolasaГ”ГҮГҳ, la chica. Sus condiciones vitales eran penosas. A partir de 1979, recuperada la democracia municipal, esta situaciв”ңв”Ӯn empezв”ңв”Ӯ a ser denunciada por personas y entidades. En 1984, finalmente, el Ayuntamiento desmantelв”ңв”Ӯ el Г”ГҮВЈzooГ”ГҮГҳ, en el que ya sв”ңв”Ӯlo quedaba la osa Г”ГҮВЈNicolasaГ”ГҮГҳ, tuerta por la agresiв”ңв”Ӯn de otro tipo de animales irracionales, indв”ңВЎgenas bв”ңВЎpedos, en este caso. Г”ГҮВЈJuanГ”ГҮГҳ habв”ңВЎa muerto antes. En la imagen, el oso Г”ГҮВЈJuanГ”ГҮГҳ nos saluda a modo de despedida, desde la distancia en el espacio y el tiempo del triste encierro en su jaula, instalada en la zona del Parque mв”ңГӯs inmediata a la calle de Mariano Alvira Lasierra.', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.64936200, -0.87037600, '0101000020E61000003E25E7C41EDAEBBFF1A1444B1ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14836201384.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14836201384.webp', 'https://www.flickr.com/photos/zaragozaantigua/14836201384/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23984, 'Dв”ңВЎa de la Victoria 1963', 'Unos vehв”ңВЎculos preparados para el combate acuв”ңГӯtico desfilan en Zaragoza ante el Convento de Jerusalв”ңВ®n, sito en la confluencia de la calle homв”ңв”Ӯnima con Isabel la Catв”ңв”Ӯlica. Participan en la celebraciв”ңв”Ӯn del "Desfile del Dв”ңВЎa de la Victoria", que desde 1940 se vino celebrando hasta 1976. в”ңГ«ste de la foto, de 1963, fue el в”ңв•‘ltimo con esa denominaciв”ңв”Ӯn, que desde 1964 pasв”ңв”Ӯ a llamarse "Desfile de la Paz", por los 25 aв”ңв–’os de pervivencia de la dictadura fascista. Hoy se sigue celebrando, con su enmascaramiento desde 1978 de "Dв”ңВЎa de las Fuerzas Armadas". Fuente: www.facebook.com/photo.php?fbid=10203727390279866&set...', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.63491700, -0.90192000, '0101000020E61000005C77F35487DCECBF5456D3F544D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15437715505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15437715505.webp', 'https://www.flickr.com/photos/zaragozaantigua/15437715505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24965, 'Torre de Bruil c.1959', 'La antigua huerta del convento de San Agustв”ңВЎn, tras su desamortizaciв”ңв”Ӯn a mediados del siglo XIX, pasв”ңв”Ӯ a propiedad del industrial Juan Bruil, que la convirtiв”ңв”Ӯ en torre de recreo con extensa zona verde visitable. Abandonada desde finales del XIX, el Ayuntamiento iniciв”ңв”Ӯ gestiones en 1953 para convertirla en parque, incluyendo el molino de aceite de la ciudad. En 1959 consiguiв”ңв”Ӯ expropiarla, cuando la finca era propiedad de Josв”ңВ® Marв”ңВЎa Monserrat y ofrecв”ңВЎa este aspecto como depв”ңв”Ӯsito de chatarra rodante, tal vez como recuerdo de los aв”ңв–’os en que fue utilizada para acoger al parque automovilв”ңВЎstico. A pesar del tiempo transcurrido, esta torre y su entorno seguв”ңВЎan siendo denominados de Bruil, nombre que se dio al parque inaugurado aв”ңв–’os despuв”ңВ®s. Al fondo de la imagen, tras los в”ңГӯrboles, la calle del Asalto. Fuente visual: Gerardo Sancho Ramo, en AMZ.', 1959, 1959, 1959, 'Anos 50', 'CASCO HISTв”ңГҙRICO', 41.64967600, -0.86985900, '0101000020E61000005133A48AE2D5EBBF807F4A9528D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15006624873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15006624873.webp', 'https://www.flickr.com/photos/zaragozaantigua/15006624873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24980, 'Calle Asalto 1974', 'Imagen no muy afortunada de calidad, aunque interesante por la insв”ңв”Ӯlita y despejada visual que desde el parque de Bruil (en obras de remodelaciв”ңв”Ӯn) habв”ңВЎa del antiguo convento barroco de las MM. Agustinas de Santa Mв”ңв”Ӯnica, cuya brumosa silueta queda difuminada al fondo. Destaca el remate de su fachada principal, en la esquina de la calle Palomar y Manuela Sancho, y de su octogonal cв”ңв•‘pula, e incluso puede apreciarse, por encima, cв”ңв”Ӯmo emerge desmochada la torre del convento de San Agustв”ңВЎn. A su izquierda, el acentuado desemboque de la calle de Cantв”ңВЎn y Gamboa en la calle Asalto. Fuente visual: Archivo Pв”ңв•‘blico Municipal, Gerardo Sancho Ramo.', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.65022200, -0.87008500, '0101000020E610000064AF777FBCD7EBBFE29178793AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23584671634.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23584671634.webp', 'https://www.flickr.com/photos/zaragozaantigua/23584671634/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24987, 'Calle Asalto 1974', 'Antiguo molino de aceite de Goicoechea en su original ubicaciв”ңв”Ӯn que confrontaba con el molino de aceite de la ciudad, y cuyos restos fueron incorporados como decoraciв”ңв”Ӯn del parque Bruil, aunque sin rв”ңв”Ӯtulo informativo alguno. Al fondo, desemboque de la calle de Cantв”ңВЎn y Gamboa en la del Asalto, y a la derecha, irrepetible vista del barroco convento de Santa Mв”ңв”Ӯnica de las Madres Agustinas, y de la desmochada torre del convento de San Agustв”ңВЎn.', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.64958900, -0.87033200, '0101000020E61000005531957EC2D9EBBFB16B7BBB25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33218893031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33218893031.webp', 'https://www.flickr.com/photos/zaragozaantigua/33218893031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24988, 'Parque Bruil 1972', 'Imagen de la pareja de osos enjaulada para supuesto disfrute del pв”ңв•‘blico, a los que se puso los nombres de Nicolasa (izquierda) y Juan (derecha), en un tiempo en la que la antigua torre de Bruil ejercв”ңВЎa de zona verde, parque de juegos infantiles, piscina, y zoolв”ңв”Ӯgico, e incluso habв”ңВЎa sugerencias para aв”ңв–’adirle la funciв”ңв”Ӯn de jardв”ңВЎn botв”ңГӯnico. Tanta acumulaciв”ңв”Ӯn de funciones, por el mismo precio, trajo poca fortuna a este espacio, sobre todo a los animales en в”ңВ®l prisioneros, como Juan y Nicolasa, a los que se arrastrв”ңв”Ӯ a una existencia bien poco edificante, que terminaron muy malamente. Fuente visual: Heraldo de Aragв”ңв”Ӯn.', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.64958900, -0.87033200, '0101000020E61000005531957EC2D9EBBFB16B7BBB25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34364011013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34364011013.webp', 'https://www.flickr.com/photos/zaragozaantigua/34364011013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25801, 'Calle Asalto 1975', 'Imagen del proceso de urbanizaciв”ңв”Ӯn del tramo de antigua muralla medieval de la calle del Asalto, denominado "de los Sitios", aunque su origen es de unos cuantos siglos antes: la cerca almenada musulmana de adobe y tapial con que cerrar el arrabal surgido entre la puerta Bab al-Qiblath y la de Bв”ңГӯb al-Yahв”ңв•‘dв”ңВЎn. Tras la conquista cristiana, esta muralla fue reforzada con ladrillo en el siglo XIV. En los siglos XVII-XVIII estos muros se convirtieron en parte del largo "paseo de las tapias" que desde el convento de San Agustв”ңВЎn circundaba casi todo el flanco sur de la ciudad, hasta la puerta del Portillo. A finales del siglo XIX este tramo fue convertido en las traseras del convento de las MM. Capuchinas, cuya entrada principal estaba en la calle de Manuela Sancho. Tras vender el terreno y trasladarse a la periferia, este espacio fue convertido en el solar de una nueva urbanizaciв”ңв”Ӯn residencial. El tramo de muralla, como consecuencia de las inimaginables implicaciones de 1808-1809, fue preservado, restaurado e integrado en el conjunto. En la imagen, capturada desde el interior del gran solar, la excavaciв”ңв”Ӯn de los cimientos de obra permite una visual de la estratigrafв”ңВЎa bajo estos muros, resultado de siglos de actividad constructiva. El gran vano arquitrabado, posiblemente uno de los antiguos trenques abiertos como paso a travв”ңВ®s de la muralla, serв”ңГӯ luego reutilizado como puerta de acceso a los garajes. Al fondo, los grandes bloques de la calle de Jorge Cocci.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTв”ңГҙRICO', 41.64933800, -0.87240400, '0101000020E610000064C91CCBBBEAEBBF6806F1811DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19144071999.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19144071999.webp', 'https://www.flickr.com/photos/zaragozaantigua/19144071999/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21317, 'Calle de Don Jaime I 1905', 'Imagen capturada en la calle de Don Jaime I y centrada en unas obras abiertas a la altura del nв”¬в•‘ 41, que fuera antigua casa del marquв”ңВ®s de San Martв”ңВЎn, con los bajos habilitados como comerciales locales. Unos aв”ңв–’os mв”ңГӯs tarde, el establecimiento de venta de vinos, aguardientes y licores de la derecha, esquinero con la antigua plazuela de San Martв”ңВЎn y Atarв”ңВ®s (luego de Ariв”ңв–’o), serв”ңВЎa reconvertido en la sede del periв”ңв”Ӯdico La Crв”ңв”Ӯnica. Fuente visual: www.todocoleccion.net/', 1905, 1905, 1905, 'Anos 1900', 'CASCO HISTв”ңГҙRICO', 41.65369300, -0.87815400, '0101000020E61000002D40DB6AD619ECBFE34F5436ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40298279371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40298279371.webp', 'https://www.flickr.com/photos/zaragozaantigua/40298279371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21531, 'Don Jaime I 1921', 'Desfile procesional del partido carlista-jaimista (por Jaime de Borbв”ңв”Ӯn y Borbв”ңв”Ӯn-Parma, pretendiente carlista al trono de Espaв”ңв–’a), Comuniв”ңв”Ӯn Tradicionalista, incluido dentro del programa de su asamblea general celebrada en Zaragoza, durante el que se habв”ңВЎa bendecido una imagen del Sagrado Corazв”ңв”Ӯn de Jesв”ңв•‘s, y ahora se la estaba trasladando en procesionaria hasta la sede del Cв”ңВЎrculo Jaimista, en la calle de Espoz y Mina nв”¬в•‘ 6. La comitiva se ha detenido para hacerse la foto a la altura, a la derecha, de la soleada plaza de Ariв”ңв–’o. El abanderado de primer plano con alpargatas blancas, sobre el tendido tranviario compartido por las lв”ңВЎneas del Arrabal, y del Gв”ңГӯllego. Fuente visual: revista "La Hormiga de Oro".', 1921, 1921, 1921, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65376000, -0.87805000, '0101000020E6100000F0164850FC18ECBF6BB75D68AED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19174999631.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19174999631.webp', 'https://www.flickr.com/photos/zaragozaantigua/19174999631/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22284, 'San Juan y San Pedro 1965', 'Fotograma del cortometraje "La persecuciв”ңв”Ӯn" (1965), de Alberto Sв”ңГӯnchez. Al fondo, portada de la desaparecida iglesia de San Juan y San Pedro, en la calle homв”ңв”Ӯnima, derribada en 1969. Identificaciв”ңв”Ӯn precisada gracias a la amable colaboraciв”ңв”Ӯn de Josв”ңВ® Vicente Royo.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65338000, -0.87747000, '0101000020E61000006A1327F73B14ECBF24EEB1F4A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15159755117.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15159755117.webp', 'https://www.flickr.com/photos/zaragozaantigua/15159755117/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22857, 'Plaza de Ariв”ңв–’o aв”ңв–’os 80', 'Plaza situada a mitad del recorrido de la calle de Don Jaime I. Estв”ңГӯ asentada sobre materiales de relleno, con posible origen de un foro romano primigenio por su situaciв”ңв”Ӯn cerca del cruce del cardo con el decumano mв”ңГӯximos. Estas caracterв”ңВЎsticas de inestabililidad propiciaron el agrietamiento de su solar, por lo que se convocв”ңв”Ӯ un concurso para su remodelaciв”ңв”Ӯn, ejecutado en 1990. La imagen reproduce el aspecto anterior a esta intervenciв”ңв”Ӯn. Al fondo a la derecha, el palacio de los Torrero, renacentista del XVI, hoy sede del Colegio de Arquitectos. Fuente visual: www.facebook.com/photo.php?fbid=1593023434259220&set=...', 1980, 1980, 1989, 'Anos 80', 'CASCO HISTв”ңГҙRICO', 41.65375800, -0.87809900, '0101000020E61000004ACFF4126319ECBFCBBF9657AED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15604406220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15604406220.webp', 'https://www.flickr.com/photos/zaragozaantigua/15604406220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24239, 'Calle de Don Jaime I c.1895', 'Imagen capturada en la antigua plazuela de San Martв”ңВЎn y Atarв”ңВ®s y centrada en la comparsa de Gigantes y Cabezudos (en la escena aparecen las parejas de Gigantes formadas por Dulcinea-Don Quijote y la Duquesa-el Duque de Villahermosa, ideadas por Fв”ңВ®lix Oroz) "comparseando" por la calle de Don Jaime I, con el telв”ңв”Ӯn de fondo edilicio del Gran Hotel de las Cuatro Naciones y del Universo, en el nв”¬в•‘ 52 de esa vв”ңВЎa. Este hotel se construyв”ңв”Ӯ en 1860 donde estuviera la casa del marquв”ңВ®s de Ariв”ңв–’o, siendo derribado a su vez en 1973. El hijarano autor de la fotografв”ңВЎa era titular de la farmacia de la calle Mayor, y habв”ңВЎa desempeв”ңв–’ado un destacado papel durante la reciente epidemia de Cв”ңв”Ӯlera que en 1885 habв”ңВЎa ocasionado en Zaragoza mв”ңГӯs de dos mil vв”ңВЎctimas mortales.', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65371500, -0.87798300, '0101000020E6100000FC34EECD6F18ECBFCBF3E0EEACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48546091246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48546091246.webp', 'https://www.flickr.com/photos/zaragozaantigua/48546091246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24345, 'San Juan y San Pedro c.1942', 'AHPZ-Archivo Fotogrв”ңГӯfico Josв”ңВ® Galiay, (SF). Torre de la Iglesia de San Juan y San Pedro. Captura realizada desde el antiguo edificio del nв”¬в•‘ 48 de la calle Don Jaime, cuyas traseras daban a la calle del Refugio, frente al modernista nв”¬в•‘ 3 de la calle San Jorge, del que se ve un pedacito.', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTв”ңГҙRICO', 41.65331400, -0.87740900, '0101000020E6100000FFE9060ABC13ECBF6D020CCB9FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700941137.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700941137.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700941137/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24432, 'Iglesia de San Juan y San Pedro 1966', 'Desde la altura del nв”¬в•‘ 10 de la calle del Refugio, una instantв”ңГӯnea capturada durante el derribo de la iglesia de San Juan y San Pedro en la primavera de 1966, con detalle de uno de los operarios mirando a cв”ңГӯmara justo en la medianera entre la torre mudв”ңВ®jar de la iglesia (considerada un hito artв”ңВЎstico) y el vecino edificio del nв”¬в•‘ 2 de la calle de San Juan y San Pedro, que tambiв”ңВ®n fue derribado en ese momento para asolar el conjunto y permitir luego la construcciв”ңв”Ӯn del actual edificio del nв”¬в•‘ 8 de la calle del Refugio. Al fondo, traseras del veterano inmueble del nв”¬в•‘ 3-5 de la calle de San Jorge.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65337800, -0.87760800, '0101000020E6100000ADA7565F5D15ECBF83F6EAE3A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52764209260.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52764209260.webp', 'https://www.flickr.com/photos/zaragozaantigua/52764209260/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24450, 'Don Jaime I, 1912', '"La Crв”ңв”Ӯnica" fue un diario zaragozano de carв”ңГӯcter regionalista, que apareciв”ңв”Ӯ el 1 de octubre de 1912. Su sede estaba en la Calle Don Jaime I nв”¬в•‘ 41. Dejв”ңв”Ӯ de editarse en 1920. La imagen corresponde al dв”ңВЎa 12 de Noviembre de 1912: en la pizarra se ha escrito "Asesinato de Canalejas", entonces Presidente del Gobierno.', 1912, 1912, 1912, 'Anos 10', 'CASCO HISTв”ңГҙRICO', 41.65364000, -0.87813900, '0101000020E6100000D8F2CAF5B619ECBFC1ADBB79AAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15330662517.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15330662517.webp', 'https://www.flickr.com/photos/zaragozaantigua/15330662517/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25594, 'Taquillas Romareda 1965', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/setiembre 1965. La cola de las taquillas de los estadios de fв”ңв•‘tbol, como el municipal de la Romareda, son escenarios donde encontrar variada fauna en pelaje y actitudes. Esta caprina estampa es bastante peculiar, pero no tanto en unos aв”ңв–’os en que la zona de la Romareda aв”ңв•‘n era un lugar de encuentro entre el agro y la urbe. La tranquilidad del rebaв”ңв–’o, y del pastor, denota que no estamos en trepidante jornada de liga.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63614900, -0.90093200, '0101000020E6100000976F7D586FD4ECBF0A3197546DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14665033738.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14665033738.webp', 'https://www.flickr.com/photos/zaragozaantigua/14665033738/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25144, 'Palacio de Ariв”ңв–’o 1650', '"Zaguв”ңГӯn de la casa de los Marqueses de Ariв”ңв–’o de Zaragoza". Dibujo de Valentв”ңВЎn Carderera Solano, realizado en 1855, con una vista del ingreso al patio interior de este desaparecido palacio o casona seв”ңв–’orial de fв”ңГӯbrica renacentista, con varias ampliaciones y fases constructivas entre los siglos XVI y XVII. Estaba situado en la calle Baja de San Pedro, en la alargada y estrecha manzana entre las calles Alta de San Pedro, Mayor, y Refugio. En el siglo XIX fue reconvertido en la "Fonda Cuatro Naciones", y allв”ңВЎ tuvo lugar el banquete que ofreciв”ңв”Ӯ en 1843 el Ayuntamiento para celebrar la jura de la Constituciв”ңв”Ӯn de 1837 por Isabel II. Mв”ңГӯs adelante, cuando se llevв”ңв”Ӯ a cabo el proceso de realineaciв”ңв”Ӯn y ensanche de la nueva calle de Don Jaime I, como suma de las calles Cuchillerв”ңВЎa, Virgen del Rosario, Baja de San Pedro, y San Gil, este palacio serв”ңГӯ derribado, como otras casonas, la antigua y cercana iglesia de San Pedro Apв”ңв”Ӯstol, y la iglesia parroquial de Santiago el Mayor. Sobre su solar serв”ңГӯ levantado, al poco, el nuevo "Hotel Universo y Cuatro Naciones", frente a la plaza redenominada de Ariв”ңв–’o, antigua de San Martв”ңВЎn. Fuente visual: ceres.mcu.es/', 1650, 1650, 1650, 'Siglo XIX', 'CASCO HISTв”ңГҙRICO', 41.65371700, -0.87787500, '0101000020E6100000643BDF4F8D17ECBF6CEBA7FFACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24880274002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24880274002.webp', 'https://www.flickr.com/photos/zaragozaantigua/24880274002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25664, 'Plaza de Ariв”ңв–’o c.1969', 'Ensanche de la calle de Don Jaime que fuera plazuela de San Martв”ңВЎn y Atarв”ңВ®s, y luego plaza de Ariв”ңв–’o, en una imagen centrada en la antigua casa del marquв”ңВ®s de San Martв”ңВЎn, aв”ңв–’os despuв”ңВ®s derribada.', 1969, 1969, 1969, 'Anos 60', 'CASCO HISTв”ңГҙRICO', 41.65375800, -0.87809900, '0101000020E61000004ACFF4126319ECBFCBBF9657AED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22135854186.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22135854186.webp', 'https://www.flickr.com/photos/zaragozaantigua/22135854186/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25684, 'Albert Einstein 1923', 'En el centro, el fв”ңВЎsico Albert Einstein, posando el dв”ңВЎa de su 44 cumpleaв”ңв–’os en un salв”ңв”Ӯn del Hotel Universo y de las Cuatro Naciones, en la calle de Don Jaime I nв”¬в•‘ 52, frente a la plaza de Ariв”ңв–’o, el miв”ңВ®rcoles 14 de marzo de 1923. La instantв”ңГӯnea se tomв”ңв”Ӯ tras una pequeв”ңв–’a Г”ГҮВЈfiesta aragonesaГ”ГҮГҳ, en la que la niв”ңв–’a que le acompaв”ңв–’a acababa de bailar una jota. A su lado, Elsa, la esposa de Einstein. Tras ellos, de pie, el catedrв”ңГӯtico de Fв”ңВЎsica Jerв”ңв”Ӯnimo Vecino Varona, el pianista Emil von Saв”ңв•қer (alojado en el mismo hotel) y Manuel Lorenzo Pardo, secretario de la Academia de Ciencias. Completan el cuadro los miembros de la rondalla. El cв”ңВ®lebre alemв”ңГӯn se marchв”ңв”Ӯ este mismo dв”ңВЎa de Zaragoza, a donde habв”ңВЎa llegado el dв”ңВЎa 12 procedente de Madrid, tras ofrecer sendas conferencias el lunes y el martes en la Facultad de Medicina y Ciencias.', 1923, 1923, 1923, 'Anos 20', 'CASCO HISTв”ңГҙRICO', 41.65378200, -0.87792100, '0101000020E61000007A17EFC7ED17ECBF535BEA20AFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52738829138.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52738829138.webp', 'https://www.flickr.com/photos/zaragozaantigua/52738829138/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23987, 'La Hв”ңВЎpica 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Junio 1966. Imagen de la entrega de trofeos en el transcurso de una fiesta en "La Hв”ңВЎpica". A la izquierda, la calle San Francisco de Borja.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.64036700, -0.90232200, '0101000020E610000011C30E63D2DFECBF0438BD8BF7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15533950877.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15533950877.webp', 'https://www.flickr.com/photos/zaragozaantigua/15533950877/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20940, 'Torre Nueva 1504', 'Dibujo del arquitecto Francisco в”ңГ¬в”ңв–’iguez Almech recreando el que hubiera sido el original estado de la Torre Nueva de Zaragoza, desprovista del chapitel y remate que en su в”ңв•‘ltima versiв”ңв”Ӯn (1746) perdurв”ңв”Ӯ hasta su eliminaciв”ңв”Ӯn en 1878 como paso previo al derribo culminado en 1893. La plв”ңГӯstica de este remate recuerda mв”ңГӯs a los alminares de la Saraqusta islв”ңГӯmica, que a las torres de principios del siglo XVI. A pesar de las dudas, y siguiendo las dataciones de la documentaciв”ңв”Ӯn conservada del siglo XVIII, в”ңГ¬в”ңв–’iguez datв”ңв”Ӯ la torre en 1504. El dibujo recrea desde cierta altura la torre en su tradicional entorno de la plaza de San Felipe, con un mercadillo instalado a sus pies. Tras ella y a la derecha, la casona de los Cerdв”ңГӯn de Escatrв”ңв”Ӯn con su rotundo torreв”ңв”Ӯn esquinero. A la izquierda, la casa del marquв”ңВ®s de Villaverde, y la iglesia de San Felipe con su traza barroca de bastante tiempo despuв”ңВ®s.', 1504, 1504, 1504, 'Siglo XIX', 'CENTRO', 41.65476500, -0.88213500, '0101000020E6100000D105F52D733AECBF60C8EA56CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50012247372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50012247372.webp', 'https://www.flickr.com/photos/zaragozaantigua/50012247372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20968, 'La Tour penchв”ңВ®e 1832', '"La Tour penchв”ңВ®e de Saragosse". Xilografв”ңВЎa de Pharamon Blanchard coloreada a mano. Viaje pintoresco a Espaв”ңв–’a, 1832. A los pies de la Torre Nueva, comparsa de gigantones, los precedentes de los actuales gigantes y cabezudos.', 1832, 1832, 1832, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19058875165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19058875165.webp', 'https://www.flickr.com/photos/zaragozaantigua/19058875165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20978, 'Torre Nueva 1858', '"Plantas, secciв”ңв”Ӯn y alzado de la Torre Nueva de esta ciudad, vista por donde presenta la mayor inclinaciв”ңв”Ӯn, y proyecto de reparaciв”ңв”Ӯn en su parte inferior, con arreglo a lo prevenido por la Real Acacdemia de Nobles Artes de San Fernando en 18 de septiembre de 1849 mandado llevar a devido cumplimiento en Real orden de 5 de octubre del mismo aв”ңв–’o", Josв”ңВ® Yarza y Joaquв”ңВЎn Gironza, Zaragoza, 29 de mayo de 1858. Acabada en 1512, la Torre Nueva de Zaragoza se derribв”ңв”Ӯ en 1892. Fuente: AMZ.', 1858, 1858, 1858, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20421586814.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20421586814.webp', 'https://www.flickr.com/photos/zaragozaantigua/20421586814/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20997, 'Calle de Contamina 1855', 'Dibujo de Valentв”ңВЎn Carderera centrado en la monumental escalera de acceso a la antigua casa de la familia Virto de Vera en la calle de Contamina, cuando su propiedad era ya del emprendedor Joaquв”ңВЎn Marв”ңВЎn, poco antes de ser expropiada y derribada durante el radical ensanche y alineaciв”ңв”Ӯn de la nueva calle de Alfonso I. Esta gran casa habilitaba un paso, denominado de Virto, que comunicaba las calles de Contamina y de la Salud, casi literalmente por donde serв”ңВЎa trazado el nuevo vial impulsado por el empecinado alcalde Antonio Candalija y Uribe. Joaquв”ңВЎn Marв”ңВЎn habв”ңВЎa comprado la casa a los duques de Villahermosa, cerrando de esta forma el traspaso del inmueble entre algunas de las mв”ңГӯs selectas sagas de la hidalguв”ңВЎa, infanzonв”ңВЎa y nobleza local (Azlor, Virto de Vera, Fuembuena-Lierta, Villahermosa). Fuente visual: Archivo Palacio Villahermosa (Pedrola), en Manuel Garcв”ңВЎa Guatas, Los в”ңГӯlbumes de Pedrola. Apuntes y acuarelas de Valentв”ңВЎn Carderera en los в”ңГӯlbumes del palacio de los Duques de Villahermosa de Pedrola, IFC, 2017.', 1855, 1855, 1855, 'Siglo XIX', 'CENTRO', 41.65474300, -0.88050300, '0101000020E6100000D8F4A0A0142DECBF79245E9ECED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38894108700.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38894108700.webp', 'https://www.flickr.com/photos/zaragozaantigua/38894108700/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21003, 'Torre Nueva c.1865', 'Fotografв”ңВЎa realizada por Josв”ңВ® Martв”ңВЎnez Sв”ңГӯnchez, e incorporada en 1868 al Archivo de Laurent. Fuente: Archivo Ruiz Vernacci, Fototeca del Patrimonio Histв”ңв”Ӯrico (www.mcu.es/).', 1865, 1865, 1865, 'Siglo XIX', 'CENTRO', 41.65471700, -0.88217300, '0101000020E610000031410DDFC23AECBF4F9143C4CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14679984819.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14679984819.webp', 'https://www.flickr.com/photos/zaragozaantigua/14679984819/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21012, 'Torre Nueva 1860', 'Zaragoza. Torre Nueva. Fuente visual: Charles Clifford, en upload.wikimedia.org/wikipedia/commons/e/e4/Charles_Cliff...', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15652599370.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15652599370.webp', 'https://www.flickr.com/photos/zaragozaantigua/15652599370/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21015, 'Torre Nueva 1867', '"Torre Nueva de Zaragoza", xilografв”ңВЎa incluida en la Crв”ңв”Ӯnica general de Espaв”ңв–’a, Madrid, 1867.', 1867, 1867, 1867, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19335525140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19335525140.webp', 'https://www.flickr.com/photos/zaragozaantigua/19335525140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21022, 'Calle Alfonso 1867', '"Proyecto de la nueva calle de Don Alfonso I y de las que afluyen a la misma", Segundo Dв”ңВЎaz, Zaragoza, 3 de mayo de 1867. La apertura de la calle de Alfonso I fue la mayor operaciв”ңв”Ӯn de reorganizaciв”ңв”Ӯn urbanв”ңВЎstica del siglo XIX en Zaragoza. Se trataba de comunicar el Coso Alto con la plaza del Pilar en lв”ңВЎnea recta, para favorecer el comercio. En 1858 se iniciв”ңв”Ӯ el debate del proceso: abrir la calle del Trenque hasta el Pilar pasando por las de Fuenclara, Montera (Candalija), Torre Nueva, Contamina, Salud (Roda, Santa Isabel), Platerв”ңВЎa (Manifestaciв”ңв”Ӯn), Mayor, Concepciв”ңв”Ӯn (Prudencio), Santa Marв”ңВЎa la Mayor (Santiago) y Los Navarros. Josв”ңВ® de Yarza entregв”ңв”Ӯ el proyecto en 1860. Los derribos se produjeron entre noviembre de 1866 y marzo de 1867. Fuente: AMZ.', 1867, 1867, 1867, 'Siglo XIX', 'CENTRO', 41.65437800, -0.88107500, '0101000020E6100000A857CA32C431ECBF679C86A8C2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20845103658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20845103658.webp', 'https://www.flickr.com/photos/zaragozaantigua/20845103658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21028, 'Torre Nueva c.1860', '"Vista de Zaragoza con la Torre Nueva". Autor anв”ңв”Ӯnimo, posiblemente Mariano Jв”ңв•‘dez. Desde la torre de la iglesia parroquial de San Gil, una extraordinaria vista centrada en la superlativa Torre Nueva con su triple chapitel. A su izquierda, la barroca iglesia parroquial de San Felipe. A su derecha, inmediato, el torreв”ңв”Ӯn de los Fortea, y la barroca iglesia de Santa Isabel, como propiedad de la Diputaciв”ңв”Ӯn Provincial de Zaragoza, y atendida por la Hermandad de la Sangre de Cristo.', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23819277440.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23819277440.webp', 'https://www.flickr.com/photos/zaragozaantigua/23819277440/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21029, 'Torre Nueva c.1860', '"Torre Nueva de Zaragoza". Autor anв”ңв”Ӯnimo. Torre Nueva con su triple chapitel. A su izquierda, San Felipe. Junto a ella, el torreв”ңв”Ӯn de los Fortea. A su derecha, la barroca iglesia de Santa Isabel. Fuente visual: Colecciв”ңв”Ӯn Madrazo, Museo del Prado.', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24015042032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24015042032.webp', 'https://www.flickr.com/photos/zaragozaantigua/24015042032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21032, 'Iglesia de San Felipe 1868', '"Saragossa - Door of San Felipe", foto Frank Mason Good. Imagen centrada en la puerta de la iglesia de San Felipe, con vista parcial de la Torre Nueva a la derecha. Fuente: www.getty.edu/art/collection/objects/72868/frank-mason-go...', 1868, 1868, 1868, 'Siglo XIX', 'CENTRO', 41.65454000, -0.88215800, '0101000020E6100000DCF3FC69A33AECBF40F67AF7C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26410444492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26410444492.webp', 'https://www.flickr.com/photos/zaragozaantigua/26410444492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21034, 'Torre Nueva c.1860', 'Vista de la Torre Nueva posiblemente capturada desde la altura del gabinete que Mariano Jв”ңв•‘dez tuvo en el nв”¬в•‘ 35 del Coso. Fuente: Mariano Jв”ңв•‘dez y Ortiz. Colecciв”ңв”Ӯn Antonio Arguas Perdiguer. Libro Primeros tiempos de la fotografв”ңВЎa en Zaragoza.', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65477600, -0.88212600, '0101000020E610000004711E4E603AECBF541A31B3CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27965303194.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27965303194.webp', 'https://www.flickr.com/photos/zaragozaantigua/27965303194/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21052, 'Colegio de las Vв”ңВЎrgenes s.XIX', 'Colegio de las Vв”ңВЎrgenes de Zaragoza. Valentв”ңВЎn Carderera. Lв”ңГӯpiz y acuarela sobre papel. Entre 1831 y 1880. Fuente: "Viaje artв”ңВЎstico por Aragв”ңв”Ӯn de Valentв”ңВЎn Carderera", Josв”ңВ® Marв”ңВЎa Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaciв”ңв”Ӯn Lв”ңГӯzaro Galdiano, 2013.', 1874, 1870, 1879, 'Siglo XIX', 'CENTRO', 41.65410000, -0.88014600, '0101000020E61000002191B6F1272AECBF24287E8CB9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14775475197.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14775475197.webp', 'https://www.flickr.com/photos/zaragozaantigua/14775475197/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21061, 'Torre Nueva c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Cв”ңВЎa. "La Torre nueva в”ңв”Ӯ torre inclinada".', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65470100, -0.88213000, '0101000020E61000005F419AB1683AECBF4AD40B3ECDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14866725795.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14866725795.webp', 'https://www.flickr.com/photos/zaragozaantigua/14866725795/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21062, 'Torre Nueva 1871', 'La Torre Nueva, Pablo Gonzalvo (1827-1896), 1871. в”ңГҙleo sobre lienzo.', 1871, 1871, 1871, 'Siglo XIX', 'CENTRO', 41.65473000, -0.88212200, '0101000020E6100000A9A0A2EA573AECBFE4DA5031CED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14901450978.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14901450978.webp', 'https://www.flickr.com/photos/zaragozaantigua/14901450978/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21063, 'Calle de la Torre Nueva 1870', 'Instantв”ңГӯnea de la Torre Nueva sobresaliendo por encima del tramo de los nв”ңв•‘meros pares de la calle Torre Nueva comprendido entre la calle del Ciprв”ңВ®s (desde donde se habrв”ңВЎa capturado la imagen, desde cierta altura), hasta la plaza de San Felipe (al fondo). Fuente visual: original del londinense Frank Mason Good, publicada en el libro de viajes "Spain and the spaniards", Edmondo De Amicis, ediciв”ңв”Ӯn 1895. ("Espaв”ңв–’a", viaje durante el reinado de Amadeo I de Saboya).', 1870, 1870, 1870, 'Siglo XIX', 'CENTRO', 41.65411900, -0.88124700, '0101000020E6100000EF5696E82C33ECBF9B58E02BBAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15159300578.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15159300578.webp', 'https://www.flickr.com/photos/zaragozaantigua/15159300578/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21078, 'Calle Torre Nueva c.1877', 'Imagen en altura de la calle Torre Nueva, desde la calle de Alfonso I. Al fondo, la torre que dio nombre a la calle. La denominaciв”ңв”Ӯn de la calle se mantiene. La torre, no. Fuente visual: Jean Laurent y Cв”ңВЎa, Archivo Ruiz Vernacci (Fototeca del Patrimonio Histв”ңв”Ӯrico, www.mcu.es/)', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22527527080.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22527527080.webp', 'https://www.flickr.com/photos/zaragozaantigua/22527527080/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21079, 'Torre Nueva c.1877', 'Segunda de las imв”ңГӯgenes en altura de la calle Torre Nueva, capturadas por Laurent y Cв”ңВЎa desde la calle de Alfonso I, realizada despuв”ңВ®s que la anterior, y aprovechando la anchura de la calle Torre Nueva para conseguir la mв”ңГӯxima visual vertical de cuerpo entero posible. El reloj lleva la fecha de fabricaciв”ңв”Ӯn de "1827", y seв”ңв–’ala las 19.05 horas. Fuente visual: Jean Laurent y Cв”ңВЎa, Archivo Ruiz Vernacci (Fototeca del Patrimonio Histв”ңв”Ӯrico, www.mcu.es/)', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22639481339.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22639481339.webp', 'https://www.flickr.com/photos/zaragozaantigua/22639481339/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21081, 'Torre Nueva c.1870', '"Leaning Tower Saragossa". Tarjeta ilustrada o cromo, inserta en un paquete de cigarrillos Hignett. Se trata del nв”ңв•‘mero 43 de una serie de 50 "interesantes edificios". Londres, ca. 1870. Fuente: The New York Public Library.', 1870, 1870, 1870, 'Siglo XIX', 'CENTRO', 41.65477200, -0.88213600, '0101000020E6100000E8F9D346753AECBF132BA391CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24562501084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24562501084.webp', 'https://www.flickr.com/photos/zaragozaantigua/24562501084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21089, 'Torre Nueva c.1870', 'Imagen de la Torre Nueva emergente desde la plaza de San Felipe, en este caso enmarcada entre la torre de la iglesia de San Felipe, a la izquierda, y la torre de la iglesia de San Pablo Apв”ңв”Ӯstol, a la derecha. La captura se ha realizado posiblemente desde la altura del inmueble de la calle de Alfonso I esquinero con la calle de la Torre Nueva.', 1870, 1870, 1870, 'Siglo XIX', 'CENTRO', 41.65472500, -0.88211400, '0101000020E6100000F3FFAA23473AECBFD26F5F07CED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49828157273.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49828157273.webp', 'https://www.flickr.com/photos/zaragozaantigua/49828157273/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21090, 'Torre Nueva c.1877', 'Grabado basado en una referencial toma fotogrв”ңГӯfica realizada por J. Laurent y C.в”¬В¬ desde la altura de la calle Torrenueva y centrada en la Torre Nueva emergiendo de la plaza de San Felipe, en un encuadre que la centra inclinada entre la torrecilla de la iglesia de San Felipe, la antigua Casa de Argillo, la torre de la Iglesia de San Pablo y el Torreв”ңв”Ӯn de los Cerdв”ңГӯn de Escatrв”ңв”Ӯn. Fue publicado en 1891 en La Ilustraciв”ңв”Ӯn espaв”ңв–’ola y americana, cuando comenzaban a arreciar las voces de quienes impulsaban su derribo "para evitar que se cayera" (que no lo hubiera hecho nunca, si le hubieran dado algo de tiempo), si bien la foto era bastante anterior.', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65473300, -0.88202800, '0101000020E61000005000C5C89239ECBF554E7B4ACED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52420058939.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52420058939.webp', 'https://www.flickr.com/photos/zaragozaantigua/52420058939/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21102, 'Torre Nueva 1889', 'Tour neuve (penchв”ңВ®e). J. Lв”ңВ®vy et Cie, 1889. Vista de la Torre Nueva de Zaragoza. Fuente: Zaragoza en la mirada ajena. Cortes de Aragв”ңв”Ӯn, 2012', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18804954241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18804954241.webp', 'https://www.flickr.com/photos/zaragozaantigua/18804954241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21131, 'Torre Nueva 1889', 'Imagen capturada desde cierta altura en la calle de Monterde y centrada en la referencial Torre Nueva (ya desmochada de su triple chapitel barroco) de la plaza de San Felipe, flanqueada por la iglesia homв”ңв”Ӯnima, la casa del marquв”ңВ®s de Villaverde, y la casa de los Cerdв”ңГӯn de Escatrв”ңв”Ӯn.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65472200, -0.88213500, '0101000020E6100000D105F52D733AECBF61FC34EECDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42455047004.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42455047004.webp', 'https://www.flickr.com/photos/zaragozaantigua/42455047004/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21185, 'Plaza de San Felipe 1890', 'Imagen centrada, desde cierta altura, en el macizo torreв”ңв”Ӯn esquinero bajomedieval que culmina la antigua casa de los Cerdв”ңГӯn de Escatrв”ңв”Ӯn, y que presenta un notable desarrollo en altura correspondiente con un aв”ңв–’adido del siglo XVI, posiblemente con funciones de solanar, que fue eliminado durante el proceso de restauraciв”ңв”Ӯn que en la dв”ңВ®cada de los ochenta del pasado siglo XX habrв”ңВЎa de darle su aspecto actual. A la izquierda, vista parcial del poligonal basamento y alzado de la Torre Nueva. Fuente visual: "Torreв”ңв”Ӯn de la Casa Fortea", fototipia de Joarizti y Mariezcurrena, en Г”ГҮВЈZaragoza Artв”ңВЎstica, Monumental e Histв”ңв”ӮricaГ”ГҮГҳ, Anselmo y Pedro Gascв”ңв”Ӯn de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65488800, -0.88204800, '0101000020E6100000171230BABC39ECBF7C45B75ED3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34295666586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34295666586.webp', 'https://www.flickr.com/photos/zaragozaantigua/34295666586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21208, 'Joyerв”ңВЎa Aladrв”ңВ®n 1905', 'Fundada en 1885, el local es obra del arquitecto Luis Aladrв”ңВ®n. Situada en la calle Alfonso I 25 de Zaragoza, esquina Contamina. Fuente: fotoszgzmemoria.blogspot.com.es/2013/04/joyeria-ajdren-de...', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.65468700, -0.88060900, '0101000020E61000004206F2ECF22DECBFE50E9BC8CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14939607549.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14939607549.webp', 'https://www.flickr.com/photos/zaragozaantigua/14939607549/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21266, 'Plaza San Felipe c.1900', 'Vista de la plaza de San Felipe de Zaragoza, con la iglesia homв”ңв”Ӯnima, a principios del siglo XX. Fuente: AMZ.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65454900, -0.88237100, '0101000020E6100000C80A7E1B623CECBF9450FA42C8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20900626228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20900626228.webp', 'https://www.flickr.com/photos/zaragozaantigua/20900626228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
